import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum BrewMethod {
  ESPRESSO = 'Espresso',
  POUR_OVER = 'Pour Over',
  AEROPRESS = 'AeroPress',
  FRENCH_PRESS = 'French Press',
  V60 = 'V60',
  CHEMEX = 'Chemex'
}

export enum RoastLevel {
  LIGHT = 'Light',
  MEDIUM_LIGHT = 'Medium-Light',
  MEDIUM = 'Medium',
  MEDIUM_DARK = 'Medium-Dark',
  DARK = 'Dark'
}

export interface CoffeeBean {
  id: string;
  name: string;
  roaster: string;
  origin: string;
  process: string;
  roastLevel: RoastLevel;
  roastDate?: string;
  purchaseDate: string;
  remainingWeight: number; // in grams
  totalWeight: number;
  notes: string;
}

export interface WaterDetails {
  type: string; // e.g., TWW, Peak, Tap
  temp: number; // in Celsius
  tds?: number;
}

export interface BrewLog {
  id: string;
  coffeeId: string;
  date: string;
  method: BrewMethod;
  grinder: string;
  grindSetting: string;
  dose: number; // grams
  yield: number; // grams or ml
  brewTime: number; // seconds
  water: WaterDetails;
  machine?: string;
  rating: number; // 1-5
  tastingNotes: string[];
  parameters: Record<string, any>; // Method specific (e.g., pressure for espresso)
}

export interface CommunityRecipe {
  id: string;
  coffeeName: string;
  roasterName: string;
  author: string;
  method: BrewMethod;
  description: string;
  likes: number;
  parameters: Partial<BrewLog>;
}

