import React, { useState } from 'react';
import { BrewMethod, CoffeeBean, BrewLog } from '../types';

interface BrewFormProps {
  coffee: CoffeeBean;
  onSave: (log: Partial<BrewLog>) => void;
  onCancel: () => void;
}

const BrewForm: React.FC<BrewFormProps> = ({ coffee, onSave, onCancel }) => {
  const [method, setMethod] = useState<BrewMethod>(BrewMethod.ESPRESSO);
  const [dose, setDose] = useState(18);
  const [yieldVal, setYieldVal] = useState(36);
  const [time, setTime] = useState(30);
  const [grinder, setGrinder] = useState('');
  const [setting, setSetting] = useState('');
  const [temp, setTemp] = useState(93);
  const [rating, setRating] = useState(4);
  const [notes, setNotes] = useState('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSave({
      coffeeId: coffee.id,
      date: new Date().toISOString(),
      method,
      dose,
      yield: yieldVal,
      brewTime: time,
      grinder,
      grindSetting: setting,
      water: { type: 'Filtered', temp },
      rating,
      tastingNotes: notes.split(',').map(n => n.trim()),
      parameters: method === BrewMethod.ESPRESSO ? { pressure: 9 } : {}
    });
  };

  return (
    <form onSubmit={handleSubmit} className="space-y-6 bg-white p-6 rounded-2xl shadow-xl border border-stone-200 max-w-lg mx-auto">
      <div className="flex justify-between items-center mb-4">
        <h2 className="text-2xl font-bold display-font">New Brew Log</h2>
        <button type="button" onClick={onCancel} className="text-stone-400 hover:text-stone-600">✕</button>
      </div>

      <div className="space-y-4">
        <div>
          <label className="block text-sm font-semibold text-stone-600 mb-1">Brew Method</label>
          <select 
            value={method} 
            onChange={(e) => setMethod(e.target.value as BrewMethod)}
            className="w-full bg-stone-50 border border-stone-200 rounded-lg p-3 outline-none focus:ring-2 focus:ring-amber-500"
          >
            {Object.values(BrewMethod).map(m => <option key={m} value={m}>{m}</option>)}
          </select>
        </div>

        <div className="grid grid-cols-2 gap-4">
          <div>
            <label className="block text-sm font-semibold text-stone-600 mb-1">Dose (g)</label>
            <input type="number" step="0.1" value={dose} onChange={e => setDose(Number(e.target.value))} className="w-full bg-stone-50 border border-stone-200 rounded-lg p-3" />
          </div>
          <div>
            <label className="block text-sm font-semibold text-stone-600 mb-1">Yield (g/ml)</label>
            <input type="number" step="0.1" value={yieldVal} onChange={e => setYieldVal(Number(e.target.value))} className="w-full bg-stone-50 border border-stone-200 rounded-lg p-3" />
          </div>
        </div>

        <div className="grid grid-cols-2 gap-4">
          <div>
            <label className="block text-sm font-semibold text-stone-600 mb-1">Grinder</label>
            <input type="text" placeholder="e.g. Niche Zero" value={grinder} onChange={e => setGrinder(e.target.value)} className="w-full bg-stone-50 border border-stone-200 rounded-lg p-3" />
          </div>
          <div>
            <label className="block text-sm font-semibold text-stone-600 mb-1">Setting</label>
            <input type="text" placeholder="e.g. 15.5" value={setting} onChange={e => setSetting(e.target.value)} className="w-full bg-stone-50 border border-stone-200 rounded-lg p-3" />
          </div>
        </div>

        <div>
          <label className="block text-sm font-semibold text-stone-600 mb-1">Brew Time (sec)</label>
          <input type="number" value={time} onChange={e => setTime(Number(e.target.value))} className="w-full bg-stone-50 border border-stone-200 rounded-lg p-3" />
        </div>

        <div>
          <label className="block text-sm font-semibold text-stone-600 mb-1">Tasting Notes (comma separated)</label>
          <textarea value={notes} onChange={e => setNotes(e.target.value)} className="w-full bg-stone-50 border border-stone-200 rounded-lg p-3 h-24" placeholder="Milk chocolate, stone fruit, balanced..."></textarea>
        </div>

        <div>
          <label className="block text-sm font-semibold text-stone-600 mb-1">Rating (1-5)</label>
          <div className="flex gap-2">
            {[1,2,3,4,5].map(star => (
              <button 
                key={star} 
                type="button" 
                onClick={() => setRating(star)}
                className={`p-2 rounded-lg transition-colors ${rating >= star ? 'text-amber-500' : 'text-stone-300'}`}
              >
                <svg className="w-8 h-8 fill-current" viewBox="0 0 20 20"><path d="M9.049 2.927c.3-.921 1.603-.921 1.902 0l1.07 3.292a1 1 0 00.95.69h3.462c.969 0 1.371 1.24.588 1.81l-2.8 2.034a1 1 0 00-.364 1.118l1.07 3.292c.3.921-.755 1.688-1.54 1.118l-2.8-2.034a1 1 0 00-1.175 0l-2.8 2.034c-.784.57-1.838-.197-1.539-1.118l1.07-3.292a1 1 0 00-.364-1.118L2.98 8.72c-.783-.57-.38-1.81.588-1.81h3.461a1 1 0 00.951-.69l1.07-3.292z" /></svg>
              </button>
            ))}
          </div>
        </div>
      </div>

      <div className="flex gap-4 pt-4">
        <button 
          type="button" 
          onClick={onCancel}
          className="flex-1 py-3 px-4 bg-stone-100 text-stone-600 rounded-xl font-bold hover:bg-stone-200 transition-colors"
        >
          Cancel
        </button>
        <button 
          type="submit"
          className="flex-1 py-3 px-4 bg-amber-800 text-white rounded-xl font-bold hover:bg-amber-900 shadow-lg shadow-amber-900/20 transition-all"
        >
          Save Brew
        </button>
      </div>
    </form>
  );
};

export default BrewForm;

import React, { useState, useEffect } from 'react';
import { CoffeeBean, BrewLog, RoastLevel, BrewMethod } from './types';
import { Icons, COLORS } from './constants';
import CoffeeCard from './components/CoffeeCard';
import BrewForm from './components/BrewForm';
import { getBrewAdvice, searchCommunityRecipes } from './services/geminiService';

// Mock initial data
const INITIAL_COFFEES: CoffeeBean[] = [
  {
    id: '1',
    name: 'Ethiopia Sidamo',
    roaster: 'Proud Mary',
    origin: 'Ethiopia',
    process: 'Washed',
    roastLevel: RoastLevel.LIGHT,
    purchaseDate: '2024-03-01',
    remainingWeight: 180,
    totalWeight: 250,
    notes: 'Incredible floral and tea-like notes.'
  },
  {
    id: '2',
    name: 'Monarch Blend',
    roaster: 'Onyx Coffee Lab',
    origin: 'Blend',
    process: 'Mixed',
    roastLevel: RoastLevel.MEDIUM,
    purchaseDate: '2024-02-25',
    remainingWeight: 45,
    totalWeight: 310,
    notes: 'Classic chocolate and berries.'
  }
];

const App: React.FC = () => {
  const [coffees, setCoffees] = useState<CoffeeBean[]>(INITIAL_COFFEES);
  const [brewLogs, setBrewLogs] = useState<BrewLog[]>([]);
  const [activeTab, setActiveTab] = useState<'library' | 'journal' | 'community'>('library');
  const [selectedCoffee, setSelectedCoffee] = useState<CoffeeBean | null>(null);
  const [showBrewForm, setShowBrewForm] = useState(false);
  const [aiAdvice, setAiAdvice] = useState<any>(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [communityRecipes, setCommunityRecipes] = useState<any[]>([]);
  const [isLoading, setIsLoading] = useState(false);

  const handleAddBrew = (log: Partial<BrewLog>) => {
    const newLog = { ...log, id: Math.random().toString(36).substr(2, 9) } as BrewLog;
    setBrewLogs([newLog, ...brewLogs]);

    // Update inventory
    setCoffees(prev => prev.map(c => 
      c.id === log.coffeeId ? { ...c, remainingWeight: Math.max(0, c.remainingWeight - (log.dose || 0)) } : c
    ));

    setShowBrewForm(false);
    setSelectedCoffee(null);
  };

  const handleFetchAdvice = async (coffee: CoffeeBean) => {
    setIsLoading(true);
    const advice = await getBrewAdvice(coffee, BrewMethod.POUR_OVER);
    setAiAdvice(advice);
    setIsLoading(false);
  };

  const handleSearchCommunity = async () => {
    setIsLoading(true);
    const results = await searchCommunityRecipes(searchQuery);
    setCommunityRecipes(results);
    setIsLoading(false);
  };

  return (
    <div className="min-h-screen pb-24 flex flex-col">
      {/* Header */}
      <header className="bg-white border-b border-stone-200 sticky top-0 z-30 px-6 py-4 flex justify-between items-center">
        <h1 className="text-2xl font-bold display-font text-stone-800">Barista <span className="text-amber-800">Journal</span></h1>
        <div className="flex items-center gap-4">
          <button className="p-2 bg-stone-50 rounded-full hover:bg-stone-100">
            <Icons.Search className="w-5 h-5 text-stone-500" />
          </button>
          <div className="w-8 h-8 rounded-full bg-stone-200 border border-stone-300 overflow-hidden">
            <img src="https://picsum.photos/100/100" alt="Avatar" />
          </div>
        </div>
      </header>

      {/* Main Content Area */}
      <main className="flex-1 max-w-4xl mx-auto w-full p-6">
        {activeTab === 'library' && (
          <div className="animate-in fade-in slide-in-from-bottom-4 duration-500">
            <div className="flex justify-between items-center mb-6">
              <h2 className="text-xl font-bold text-stone-800">Coffee Library</h2>
              <button className="bg-amber-800 text-white p-2 rounded-lg flex items-center gap-2 text-sm font-bold shadow-lg shadow-amber-900/20">
                <Icons.Plus className="w-4 h-4" /> Add Bean
              </button>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              {coffees.map(coffee => (
                <CoffeeCard 
                  key={coffee.id} 
                  coffee={coffee} 
                  onClick={(c) => setSelectedCoffee(c)} 
                />
              ))}
            </div>

            {selectedCoffee && !showBrewForm && (
              <div className="fixed inset-0 bg-black/60 backdrop-blur-sm flex items-center justify-center z-50 p-6 overflow-y-auto">
                <div className="bg-white rounded-2xl w-full max-w-2xl p-8 space-y-6 relative max-h-[90vh] overflow-y-auto">
                  <button 
                    onClick={() => {setSelectedCoffee(null); setAiAdvice(null);}} 
                    className="absolute top-4 right-4 text-stone-400 hover:text-stone-600"
                  >
                    <Icons.Plus className="w-6 h-6 rotate-45" />
                  </button>

                  <div className="flex justify-between items-start">
                    <div>
                      <p className="text-amber-800 font-bold uppercase tracking-widest text-xs mb-1">{selectedCoffee.roaster}</p>
                      <h2 className="text-4xl font-bold display-font">{selectedCoffee.name}</h2>
                      <p className="text-stone-500">{selectedCoffee.origin} • {selectedCoffee.process}</p>
                    </div>
                    <div className="text-right">
                      <div className="bg-stone-100 rounded-full px-3 py-1 text-sm font-bold text-stone-600 mb-2">
                        {selectedCoffee.roastLevel} Roast
                      </div>
                      <p className="text-xs text-stone-400">Purchased {selectedCoffee.purchaseDate}</p>
                    </div>
                  </div>

                  <div className="flex gap-4 border-y border-stone-100 py-6">
                    <button 
                      onClick={() => setShowBrewForm(true)}
                      className="flex-1 bg-amber-800 text-white py-4 rounded-xl font-bold flex items-center justify-center gap-2 hover:bg-amber-900 transition-colors"
                    >
                      <Icons.Coffee className="w-5 h-5" /> Log New Brew
                    </button>
                    <button 
                      onClick={() => handleFetchAdvice(selectedCoffee)}
                      className="flex-1 bg-amber-100 text-amber-900 py-4 rounded-xl font-bold flex items-center justify-center gap-2 hover:bg-amber-200 transition-colors"
                    >
                      {isLoading ? "Consulting AI..." : "Get AI Advice"}
                    </button>
                  </div>

                  {aiAdvice && (
                    <div className="bg-amber-50 rounded-xl p-6 border border-amber-100">
                      <h4 className="font-bold text-amber-900 mb-4 flex items-center gap-2">
                        <span className="text-xl">✨</span> Barista AI's Recommended Recipe
                      </h4>
                      <div className="grid grid-cols-3 gap-4 mb-4 text-center">
                        <div className="bg-white p-3 rounded-lg border border-amber-100">
                          <p className="text-[10px] uppercase text-stone-400 font-bold">Dose</p>
                          <p className="text-xl font-bold text-stone-800">{aiAdvice.dose}g</p>
                        </div>
                        <div className="bg-white p-3 rounded-lg border border-amber-100">
                          <p className="text-[10px] uppercase text-stone-400 font-bold">Yield</p>
                          <p className="text-xl font-bold text-stone-800">{aiAdvice.yield}g</p>
                        </div>
                        <div className="bg-white p-3 rounded-lg border border-amber-100">
                          <p className="text-[10px] uppercase text-stone-400 font-bold">Temp</p>
                          <p className="text-xl font-bold text-stone-800">{aiAdvice.temp}°C</p>
                        </div>
                      </div>
                      <div className="space-y-2 text-sm text-stone-700">
                        <p><strong>Grind:</strong> {aiAdvice.grindSize}</p>
                        <p><strong>Notes:</strong> {aiAdvice.tastingNotes.join(', ')}</p>
                        <div className="mt-4 p-3 bg-white/50 rounded-lg italic text-stone-600">
                          "{aiAdvice.instructions}"
