                      </div>
                    </div>
                  )}

                  <div className="space-y-4">
                    <h4 className="font-bold text-stone-800">Recent Brews with this Coffee</h4>
                    {brewLogs.filter(b => b.coffeeId === selectedCoffee.id).length === 0 ? (
                      <p className="text-stone-400 text-sm italic">No brew logs found for this coffee yet.</p>
                    ) : (
                      brewLogs.filter(b => b.coffeeId === selectedCoffee.id).map(log => (
                        <div key={log.id} className="bg-stone-50 p-4 rounded-xl flex justify-between items-center border border-stone-100">
                          <div>
                            <p className="font-bold text-stone-800">{log.method}</p>
                            <p className="text-xs text-stone-500">{new Date(log.date).toLocaleDateString()} • {log.grindSetting} setting</p>
                          </div>
                          <div className="flex items-center gap-1 text-amber-500">
                            {[...Array(log.rating)].map((_, i) => <Icons.Star key={i} className="w-3 h-3 fill-current" />)}
