                            </span>
                          ))}
                        </div>
                      )}
                    </div>
                  );
                })}
              </div>
            )}
          </div>
        )}

        {activeTab === 'community' && (
          <div className="animate-in fade-in slide-in-from-bottom-4 duration-500">
            <div className="bg-amber-800 rounded-3xl p-8 mb-8 text-white relative overflow-hidden">
              <div className="relative z-10">
                <h2 className="text-3xl font-bold display-font mb-2">Barista Community</h2>
                <p className="text-amber-100 mb-6">Discover and share recipes from fellow coffee lovers.</p>
                <div className="flex gap-2">
                  <input 
                    type="text" 
                    placeholder="Search by coffee, roaster or method..." 
                    className="flex-1 bg-white/10 border border-white/20 rounded-xl px-4 py-3 text-white placeholder-white/50 outline-none focus:bg-white/20"
                    value={searchQuery}
                    onChange={(e) => setSearchQuery(e.target.value)}
                  />
                  <button 
                    onClick={handleSearchCommunity}
                    disabled={isLoading}
                    className="bg-white text-amber-900 px-6 py-3 rounded-xl font-bold hover:bg-amber-50 transition-colors disabled:opacity-50"
