                        <div className="w-6 h-6 rounded-full bg-stone-300"></div>
                        <span className="text-xs font-bold text-stone-500">by {recipe.author}</span>
                      </div>
                      <button className="text-amber-800 text-xs font-bold hover:underline">View Full Recipe</button>
