            ) : (
              <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                <div className="p-4 border border-stone-200 rounded-xl bg-white flex flex-col items-center text-center">
                  <div className="w-12 h-12 bg-amber-50 rounded-full flex items-center justify-center text-amber-800 mb-4">
                    <Icons.Coffee className="w-6 h-6" />
                  </div>
                  <h4 className="font-bold text-stone-800 mb-1">Top Shared</h4>
                  <p className="text-xs text-stone-500">The highest rated recipes this week.</p>
                </div>
                <div className="p-4 border border-stone-200 rounded-xl bg-white flex flex-col items-center text-center">
                  <div className="w-12 h-12 bg-amber-50 rounded-full flex items-center justify-center text-amber-800 mb-4">
                    <Icons.Plus className="w-6 h-6" />
                  </div>
                  <h4 className="font-bold text-stone-800 mb-1">New Arrivals</h4>
                  <p className="text-xs text-stone-500">Recent coffees added to the library.</p>
                </div>
                <div className="p-4 border border-stone-200 rounded-xl bg-white flex flex-col items-center text-center">
                  <div className="w-12 h-12 bg-amber-50 rounded-full flex items-center justify-center text-amber-800 mb-4">
                    <Icons.Users className="w-6 h-6" />
                  </div>
                  <h4 className="font-bold text-stone-800 mb-1">Top Roasters</h4>
                  <p className="text-xs text-stone-500">The community's favorite roasters.</p>
                </div>
              </div>
            )}
