export default App;

export enum BrewMethod {
  ESPRESSO = 'Espresso',
  POUR_OVER = 'Pour Over',
  AEROPRESS = 'AeroPress',
  FRENCH_PRESS = 'French Press',
  V60 = 'V60',
  CHEMEX = 'Chemex'
}

export enum RoastLevel {
  LIGHT = 'Light',
  MEDIUM_LIGHT = 'Medium-Light',
  MEDIUM = 'Medium',
  MEDIUM_DARK = 'Medium-Dark',
  DARK = 'Dark'
}

export interface CoffeeBean {
  id: string;
  name: string;
  roaster: string;
  origin: string;
  process: string;
  roastLevel: RoastLevel;
  roastDate?: string;
  purchaseDate: string;
  remainingWeight: number; // in grams
  totalWeight: number;
  notes: string;
}

export interface WaterDetails {
  type: string; // e.g., TWW, Peak, Tap
  temp: number; // in Celsius
  tds?: number;
}

export interface BrewLog {
  id: string;
  coffeeId: string;
  baristaName?: string; // New field from Calibration Doc
  site?: string;        // New field from Calibration Doc (Location/Site)
  date: string;
  method: BrewMethod;
  grinder: string;
  grindSetting: string;
  dose: number; // grams
  yield: number; // grams or ml
  brewTime: number; // seconds
  pressure?: number; // New field from Calibration Doc (bar)
  shotResult?: 'Pass' | 'Fail'; // New field from Calibration Doc
  water: WaterDetails;
  machine?: string;
  rating: number; // 1-5
  tastingNotes: string[];
  parameters: Record<string, any>; 
}

export interface CommunityRecipe {
  id: string;
  coffeeName: string;
  roasterName: string;
  author: string;
  method: BrewMethod;
  description: string;
  likes: number;
  parameters: Partial<BrewLog>;
}

import React, { useState } from 'react';
import { BrewMethod, CoffeeBean, BrewLog } from '../types';

interface BrewFormProps {
  coffee: CoffeeBean;
  onSave: (log: Partial<BrewLog>) => void;
  onCancel: () => void;
}

const BrewForm: React.FC<BrewFormProps> = ({ coffee, onSave, onCancel }) => {
  const [method, setMethod] = useState<BrewMethod>(BrewMethod.ESPRESSO);
  const [baristaName, setBaristaName] = useState('');
  const [site, setSite] = useState('');
  const [machine, setMachine] = useState('');
  const [dose, setDose] = useState(18);
  const [yieldVal, setYieldVal] = useState(36);
  const [time, setTime] = useState(28);
  const [pressure, setPressure] = useState(9);
  const [shotResult, setShotResult] = useState<'Pass' | 'Fail'>('Pass');
  const [grinder, setGrinder] = useState('');
  const [setting, setSetting] = useState('');
  const [temp, setTemp] = useState(93);
  const [rating, setRating] = useState(4);
  const [notes, setNotes] = useState('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSave({
      coffeeId: coffee.id,
      baristaName,
      site,
      machine,
      date: new Date().toISOString(),
      method,
      dose,
      yield: yieldVal,
      brewTime: time,
      pressure: method === BrewMethod.ESPRESSO ? pressure : undefined,
      shotResult: method === BrewMethod.ESPRESSO ? shotResult : undefined,
      grinder,
      grindSetting: setting,
      water: { type: 'Filtered', temp },
      rating,
      tastingNotes: notes.split(',').map(n => n.trim()).filter(n => n !== ''),
      parameters: {}
    });
  };

  return (
    <form onSubmit={handleSubmit} className="space-y-5 bg-white p-6 rounded-2xl shadow-xl border border-stone-200 max-w-lg mx-auto max-h-[90vh] overflow-y-auto">
      <div className="flex justify-between items-center mb-2">
        <h2 className="text-2xl font-bold display-font">Brew Calibration Log</h2>
        <button type="button" onClick={onCancel} className="text-stone-400 hover:text-stone-600">✕</button>
      </div>

      <div className="space-y-4">
        {/* Basic Calibration Info */}
        <div className="grid grid-cols-2 gap-4">
          <div>
            <label className="block text-[10px] font-bold text-stone-400 uppercase tracking-widest mb-1">Barista Name</label>
            <input type="text" value={baristaName} onChange={e => setBaristaName(e.target.value)} className="w-full bg-stone-50 border border-stone-200 rounded-lg p-2.5 text-sm" placeholder="Your Name" />
          </div>
          <div>
            <label className="block text-[10px] font-bold text-stone-400 uppercase tracking-widest mb-1">Site / Location</label>
            <input type="text" value={site} onChange={e => setSite(e.target.value)} className="w-full bg-stone-50 border border-stone-200 rounded-lg p-2.5 text-sm" placeholder="Training Bar" />
          </div>
        </div>

        <div className="grid grid-cols-2 gap-4">
          <div>
            <label className="block text-[10px] font-bold text-stone-400 uppercase tracking-widest mb-1">Brew Method</label>
            <select 
              value={method} 
              onChange={(e) => setMethod(e.target.value as BrewMethod)}
              className="w-full bg-stone-50 border border-stone-200 rounded-lg p-2.5 text-sm outline-none focus:ring-2 focus:ring-amber-500"
            >
              {Object.values(BrewMethod).map(m => <option key={m} value={m}>{m}</option>)}
            </select>
          </div>
          <div>
            <label className="block text-[10px] font-bold text-stone-400 uppercase tracking-widest mb-1">Machine</label>
            <input type="text" value={machine} onChange={e => setMachine(e.target.value)} className="w-full bg-stone-50 border border-stone-200 rounded-lg p-2.5 text-sm" placeholder="Lineas PB" />
          </div>
        </div>

        {/* Grind Parameters */}
        <div className="grid grid-cols-2 gap-4">
          <div>
            <label className="block text-[10px] font-bold text-stone-400 uppercase tracking-widest mb-1">Grinder</label>
            <input type="text" placeholder="EK43 / Niche" value={grinder} onChange={e => setGrinder(e.target.value)} className="w-full bg-stone-50 border border-stone-200 rounded-lg p-2.5 text-sm" />
          </div>
          <div>
            <label className="block text-[10px] font-bold text-stone-400 uppercase tracking-widest mb-1">Setting</label>
            <input type="text" placeholder="15.5" value={setting} onChange={e => setSetting(e.target.value)} className="w-full bg-stone-50 border border-stone-200 rounded-lg p-2.5 text-sm" />
          </div>
        </div>

        {/* Extraction Parameters */}
        <div className="grid grid-cols-3 gap-3">
          <div>
            <label className="block text-[10px] font-bold text-stone-400 uppercase tracking-widest mb-1">Dose (g)</label>
            <input type="number" step="0.1" value={dose} onChange={e => setDose(Number(e.target.value))} className="w-full bg-stone-50 border border-stone-200 rounded-lg p-2.5 text-sm" />
          </div>
          <div>
            <label className="block text-[10px] font-bold text-stone-400 uppercase tracking-widest mb-1">Yield (g)</label>
            <input type="number" step="0.1" value={yieldVal} onChange={e => setYieldVal(Number(e.target.value))} className="w-full bg-stone-50 border border-stone-200 rounded-lg p-2.5 text-sm" />
          </div>
          <div>
            <label className="block text-[10px] font-bold text-stone-400 uppercase tracking-widest mb-1">Time (s)</label>
            <input type="number" value={time} onChange={e => setTime(Number(e.target.value))} className="w-full bg-stone-50 border border-stone-200 rounded-lg p-2.5 text-sm" />
          </div>
        </div>

        {/* Espresso Specifics */}
        {method === BrewMethod.ESPRESSO && (
          <div className="grid grid-cols-2 gap-4 bg-amber-50/50 p-4 rounded-xl border border-amber-100">
            <div>
              <label className="block text-[10px] font-bold text-amber-800 uppercase tracking-widest mb-1">Pressure (bar)</label>
              <input type="number" step="0.5" value={pressure} onChange={e => setPressure(Number(e.target.value))} className="w-full bg-white border border-amber-200 rounded-lg p-2.5 text-sm" />
            </div>
            <div>
              <label className="block text-[10px] font-bold text-amber-800 uppercase tracking-widest mb-1">Shot Result</label>
              <div className="flex bg-white rounded-lg border border-amber-200 overflow-hidden">
                <button 
                  type="button" 
                  onClick={() => setShotResult('Pass')}
                  className={`flex-1 py-2 text-xs font-bold transition-colors ${shotResult === 'Pass' ? 'bg-green-600 text-white' : 'text-stone-400 hover:bg-stone-50'}`}
                >
                  Pass
                </button>
                <button 
                  type="button" 
                  onClick={() => setShotResult('Fail')}
                  className={`flex-1 py-2 text-xs font-bold transition-colors ${shotResult === 'Fail' ? 'bg-red-600 text-white' : 'text-stone-400 hover:bg-stone-50'}`}
                >
                  Fail
                </button>
              </div>
            </div>
          </div>
        )}

        <div>
          <label className="block text-[10px] font-bold text-stone-400 uppercase tracking-widest mb-1">Taste Notes</label>
          <textarea value={notes} onChange={e => setNotes(e.target.value)} className="w-full bg-stone-50 border border-stone-200 rounded-lg p-2.5 text-sm h-20" placeholder="e.g. Bright acidity, dark chocolate, lingering finish..."></textarea>
        </div>

        <div className="flex items-center justify-between">
          <label className="text-[10px] font-bold text-stone-400 uppercase tracking-widest">Calibration Rating</label>
          <div className="flex gap-1">
            {[1,2,3,4,5].map(star => (
              <button 
                key={star} 
                type="button" 
                onClick={() => setRating(star)}
                className={`p-1 transition-colors ${rating >= star ? 'text-amber-500' : 'text-stone-300'}`}
              >
                <svg className="w-6 h-6 fill-current" viewBox="0 0 20 20"><path d="M9.049 2.927c.3-.921 1.603-.921 1.902 0l1.07 3.292a1 1 0 00.95.69h3.462c.969 0 1.371 1.24.588 1.81l-2.8 2.034a1 1 0 00-.364 1.118l1.07 3.292c.3.921-.755 1.688-1.54 1.118l-2.8-2.034a1 1 0 00-1.175 0l-2.8 2.034c-.784.57-1.838-.197-1.539-1.118l1.07-3.292a1 1 0 00-.364-1.118L2.98 8.72c-.783-.57-.38-1.81.588-1.81h3.461a1 1 0 00.951-.69l1.07-3.292z" /></svg>
              </button>
            ))}
          </div>
        </div>
      </div>

      <div className="flex gap-4 pt-4 sticky bottom-0 bg-white">
        <button 
          type="button" 
          onClick={onCancel}
          className="flex-1 py-3 px-4 bg-stone-100 text-stone-600 rounded-xl font-bold hover:bg-stone-200 transition-colors"
        >
          Cancel
        </button>
        <button 
          type="submit"
          className="flex-1 py-3 px-4 bg-amber-800 text-white rounded-xl font-bold hover:bg-amber-900 shadow-lg shadow-amber-900/20 transition-all"
        >
          Log Calibration
        </button>
      </div>
    </form>
  );
};

export default BrewForm;

import React, { useState, useEffect } from 'react';
import { CoffeeBean, BrewLog, RoastLevel, BrewMethod } from './types';
import { Icons, COLORS } from './constants';
import CoffeeCard from './components/CoffeeCard';
import BrewForm from './components/BrewForm';
import { getBrewAdvice, searchCommunityRecipes } from './services/geminiService';

// Mock initial data
const INITIAL_COFFEES: CoffeeBean[] = [
  {
    id: '1',
    name: 'Ethiopia Sidamo',
    roaster: 'Proud Mary',
    origin: 'Ethiopia',
    process: 'Washed',
    roastLevel: RoastLevel.LIGHT,
    purchaseDate: '2024-03-01',
    remainingWeight: 180,
    totalWeight: 250,
    notes: 'Incredible floral and tea-like notes.'
  },
  {
    id: '2',
    name: 'Monarch Blend',
    roaster: 'Onyx Coffee Lab',
    origin: 'Blend',
    process: 'Mixed',
    roastLevel: RoastLevel.MEDIUM,
    purchaseDate: '2024-02-25',
    remainingWeight: 45,
    totalWeight: 310,
    notes: 'Classic chocolate and berries.'
  }
];

const App: React.FC = () => {
  const [coffees, setCoffees] = useState<CoffeeBean[]>(INITIAL_COFFEES);
  const [brewLogs, setBrewLogs] = useState<BrewLog[]>([]);
  const [activeTab, setActiveTab] = useState<'library' | 'journal' | 'community'>('library');
  const [selectedCoffee, setSelectedCoffee] = useState<CoffeeBean | null>(null);
  const [showBrewForm, setShowBrewForm] = useState(false);
  const [aiAdvice, setAiAdvice] = useState<any>(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [communityRecipes, setCommunityRecipes] = useState<any[]>([]);
  const [isLoading, setIsLoading] = useState(false);

  const handleAddBrew = (log: Partial<BrewLog>) => {
    const newLog = { ...log, id: Math.random().toString(36).substr(2, 9) } as BrewLog;
    setBrewLogs([newLog, ...brewLogs]);

    // Update inventory
    setCoffees(prev => prev.map(c => 
      c.id === log.coffeeId ? { ...c, remainingWeight: Math.max(0, c.remainingWeight - (log.dose || 0)) } : c
    ));

    setShowBrewForm(false);
    setSelectedCoffee(null);
  };

  const handleFetchAdvice = async (coffee: CoffeeBean) => {
    setIsLoading(true);
    const advice = await getBrewAdvice(coffee, BrewMethod.POUR_OVER);
    setAiAdvice(advice);
    setIsLoading(false);
  };

  const handleSearchCommunity = async () => {
    setIsLoading(true);
    const results = await searchCommunityRecipes(searchQuery);
    setCommunityRecipes(results);
    setIsLoading(false);
  };

  return (
    <div className="min-h-screen pb-24 flex flex-col">
      {/* Header */}
      <header className="bg-white border-b border-stone-200 sticky top-0 z-30 px-6 py-4 flex justify-between items-center">
        <h1 className="text-2xl font-bold display-font text-stone-800">Barista <span className="text-amber-800">Journal</span></h1>
        <div className="flex items-center gap-4">
          <button className="p-2 bg-stone-50 rounded-full hover:bg-stone-100">
            <Icons.Search className="w-5 h-5 text-stone-500" />
          </button>
          <div className="w-8 h-8 rounded-full bg-stone-200 border border-stone-300 overflow-hidden">
            <img src="https://picsum.photos/100/100" alt="Avatar" />
          </div>
        </div>
      </header>

      {/* Main Content Area */}
      <main className="flex-1 max-w-4xl mx-auto w-full p-6">
        {activeTab === 'library' && (
          <div className="animate-in fade-in slide-in-from-bottom-4 duration-500">
            <div className="flex justify-between items-center mb-6">
              <h2 className="text-xl font-bold text-stone-800">Coffee Library</h2>
              <button className="bg-amber-800 text-white p-2 rounded-lg flex items-center gap-2 text-sm font-bold shadow-lg shadow-amber-900/20">
                <Icons.Plus className="w-4 h-4" /> Add Bean
