                        <div className="text-right">
                          <p className="text-xs text-stone-400">{new Date(log.date).toLocaleDateString()}</p>
                          <div className="flex gap-1 text-amber-500 mt-1">
                            {[...Array(log.rating)].map((_, i) => <Icons.Star key={i} className="w-3 h-3 fill-current" />)}
                          </div>
                        </div>
                      </div>

                      <div className="grid grid-cols-4 md:grid-cols-6 gap-2 mt-4 pt-4 border-t border-stone-50 text-center">
                        <div className="text-xs">
                          <p className="text-stone-400 font-medium">Machine</p>
                          <p className="font-bold text-stone-800 truncate">{log.machine || '-'}</p>
                        </div>
                        <div className="text-xs">
                          <p className="text-stone-400 font-medium">Dose</p>
                          <p className="font-bold text-stone-800">{log.dose}g</p>
                        </div>
                        <div className="text-xs">
                          <p className="text-stone-400 font-medium">Yield</p>
                          <p className="font-bold text-stone-800">{log.yield}g</p>
                        </div>
                        <div className="text-xs">
                          <p className="text-stone-400 font-medium">Time</p>
                          <p className="font-bold text-stone-800">{log.brewTime}s</p>
                        </div>
                        {isEspresso && (
                          <div className="text-xs">
                            <p className="text-stone-400 font-medium">Pressure</p>
                            <p className="font-bold text-stone-800">{log.pressure}b</p>
                          </div>
                        )}
                        <div className="text-xs">
                          <p className="text-stone-400 font-medium">Grinder</p>
                          <p className="font-bold text-stone-800 truncate">{log.grinder || '-'}</p>
                        </div>
                      </div>

                      {log.tastingNotes.length > 0 && (
                        <div className="mt-4 flex flex-wrap gap-2">
                          {log.tastingNotes.map(note => (
                            <span key={note} className="px-2 py-0.5 bg-stone-100 text-stone-600 rounded-md text-[10px] font-medium">
                              {note}
                            </span>
                          ))}
                        </div>
                      )}
                    </div>
                  );
                })}
              </div>
            )}
          </div>
        )}

        {activeTab === 'community' && (
          <div className="animate-in fade-in slide-in-from-bottom-4 duration-500">
            <div className="bg-amber-800 rounded-3xl p-8 mb-8 text-white relative overflow-hidden">
              <div className="relative z-10">
                <h2 className="text-3xl font-bold display-font mb-2">Barista Community</h2>
                <p className="text-amber-100 mb-6">Discover and share recipes from fellow coffee lovers.</p>
                <div className="flex gap-2">
                  <input 
                    type="text" 
                    placeholder="Search by coffee, roaster or method..." 
                    className="flex-1 bg-white/10 border border-white/20 rounded-xl px-4 py-3 text-white placeholder-white/50 outline-none focus:bg-white/20"
                    value={searchQuery}
                    onChange={(e) => setSearchQuery(e.target.value)}
                  />
                  <button 
                    onClick={handleSearchCommunity}
                    disabled={isLoading}
                    className="bg-white text-amber-900 px-6 py-3 rounded-xl font-bold hover:bg-amber-50 transition-colors disabled:opacity-50"
                  >
                    {isLoading ? "Searching..." : "Search"}
                  </button>
                </div>
              </div>
              <div className="absolute -right-10 -bottom-10 opacity-10">
                <Icons.Users className="w-64 h-64" />
              </div>
            </div>

            {communityRecipes.length > 0 ? (
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                {communityRecipes.map(recipe => (
                  <div key={recipe.id} className="bg-white p-6 rounded-2xl shadow-sm border border-stone-200">
                    <div className="flex justify-between items-start mb-4">
                      <div>
                        <span className="text-[10px] font-bold text-amber-800 uppercase tracking-widest">{recipe.method}</span>
                        <h3 className="font-bold text-xl text-stone-800 leading-tight">{recipe.coffeeName}</h3>
                        <p className="text-sm text-stone-500 font-medium">{recipe.roasterName}</p>
                      </div>
                      <div className="bg-stone-100 rounded-full px-2 py-1 flex items-center gap-1">
                        <span className="text-xs font-bold text-stone-600">{recipe.likes}</span>
                        <Icons.Star className="w-3 h-3 text-amber-500 fill-current" />
                      </div>
                    </div>
                    <p className="text-sm text-stone-600 mb-6 line-clamp-3">"{recipe.description}"</p>
                    <div className="bg-stone-50 p-3 rounded-lg text-xs font-mono text-stone-600 mb-6">
                      {recipe.recipe}
                    </div>
                    <div className="flex items-center justify-between">
                      <div className="flex items-center gap-2">
                        <div className="w-6 h-6 rounded-full bg-stone-300"></div>
                        <span className="text-xs font-bold text-stone-500">by {recipe.author}</span>
                      </div>
                      <button className="text-amber-800 text-xs font-bold hover:underline">View Full Recipe</button>
                    </div>
                  </div>
                ))}
              </div>
            ) : searchQuery && !isLoading ? (
               <div className="text-center py-10">
                <p className="text-stone-400">No community recipes found for this query.</p>
               </div>
            ) : (
              <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                <div className="p-4 border border-stone-200 rounded-xl bg-white flex flex-col items-center text-center">
                  <div className="w-12 h-12 bg-amber-50 rounded-full flex items-center justify-center text-amber-800 mb-4">
                    <Icons.Coffee className="w-6 h-6" />
                  </div>
                  <h4 className="font-bold text-stone-800 mb-1">Top Shared</h4>
                  <p className="text-xs text-stone-500">The highest rated recipes this week.</p>
                </div>
                <div className="p-4 border border-stone-200 rounded-xl bg-white flex flex-col items-center text-center">
                  <div className="w-12 h-12 bg-amber-50 rounded-full flex items-center justify-center text-amber-800 mb-4">
                    <Icons.Plus className="w-6 h-6" />
                  </div>
                  <h4 className="font-bold text-stone-800 mb-1">New Arrivals</h4>
                  <p className="text-xs text-stone-500">Recent coffees added to the library.</p>
                </div>
                <div className="p-4 border border-stone-200 rounded-xl bg-white flex flex-col items-center text-center">
                  <div className="w-12 h-12 bg-amber-50 rounded-full flex items-center justify-center text-amber-800 mb-4">
                    <Icons.Users className="w-6 h-6" />
                  </div>
                  <h4 className="font-bold text-stone-800 mb-1">Top Roasters</h4>
                  <p className="text-xs text-stone-500">The community's favorite roasters.</p>
                </div>
              </div>
            )}
          </div>
        )}
      </main>

      {/* Global Modals */}
      {showBrewForm && selectedCoffee && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-md flex items-center justify-center z-[60] p-6 overflow-y-auto">
          <BrewForm 
            coffee={selectedCoffee} 
            onSave={handleAddBrew} 
            onCancel={() => setShowBrewForm(false)} 
          />
        </div>
      )}

      {/* Navigation Bar */}
      <nav className="fixed bottom-0 left-0 right-0 bg-white/80 backdrop-blur-lg border-t border-stone-200 px-6 py-4 flex justify-around items-center z-40 max-w-lg mx-auto md:rounded-t-3xl md:shadow-2xl">
        <button 
          onClick={() => setActiveTab('library')}
          className={`flex flex-col items-center gap-1 transition-colors ${activeTab === 'library' ? 'text-amber-800' : 'text-stone-400'}`}
        >
          <Icons.Coffee className="w-6 h-6" />
          <span className="text-[10px] font-bold uppercase tracking-widest">Library</span>
        </button>
        <button 
          onClick={() => setActiveTab('journal')}
          className={`flex flex-col items-center gap-1 transition-colors ${activeTab === 'journal' ? 'text-amber-800' : 'text-stone-400'}`}
        >
          <Icons.Book className="w-6 h-6" />
          <span className="text-[10px] font-bold uppercase tracking-widest">Journal</span>
        </button>
        <button 
          onClick={() => setActiveTab('community')}
          className={`flex flex-col items-center gap-1 transition-colors ${activeTab === 'community' ? 'text-amber-800' : 'text-stone-400'}`}
        >
          <Icons.Users className="w-6 h-6" />
          <span className="text-[10px] font-bold uppercase tracking-widest">Community</span>
        </button>
      </nav>
    </div>
  );
};

export default App;

export enum BrewMethod {
  ESPRESSO = 'Espresso',
  POUR_OVER = 'Filter/Pour Over',
  AEROPRESS = 'AeroPress',
  FRENCH_PRESS = 'French Press',
  V60 = 'V60',
  CHEMEX = 'Chemex'
}

export enum RoastLevel {
  LIGHT = 'Light',
  MEDIUM_LIGHT = 'Medium-Light',
  MEDIUM = 'Medium',
  MEDIUM_DARK = 'Medium-Dark',
  DARK = 'Dark'
}

export interface CoffeeBean {
  id: string;
  name: string;
  roaster: string;
  origin: string;
  process: string;
  varietal?: string; // New from Filter Doc
  roastLevel: RoastLevel;
  roastDate?: string;
  purchaseDate: string;
  remainingWeight: number;
  totalWeight: number;
  notes: string;
}

export interface WaterDetails {
  type: string;
  temp: number;
  tds?: number;
}

export interface BrewLog {
  id: string;
  coffeeId: string;
  baristaName?: string;
  site?: string;
  date: string;
  method: BrewMethod;
  grinder: string;
  grindSetting: string;
  dose: number; 
  yield: number; // Water (g) for Filter/Aero, Yield (g) for Espresso
  brewTime: number; 
  rating: number; 
  tastingNotes: string[];

  // Espresso Specific
  pressure?: number;
  shotResult?: 'Pass' | 'Fail';
  machine?: string;

  // AeroPress Specific
  aeroPressModel?: string;
  aeroMethod?: string; // Inverted/Standard
  bloomTime?: number;
  steepTime?: number;
  agitation?: string; // yes/no

  // Filter Specific
  brewer?: string; // V60, Chemex, etc.
  ratio?: string;
  pourStructure?: string; // Pulses
  waterDetails?: WaterDetails;
}

export interface WeeklySummary {
  id: string;
  name: string;
  weekStartDate: string;
  weekEndDate: string;
  primaryGrinder: string;
  primaryBrewer: string;
  totalBrews: number;
  avgDose: number;
  avgRatio: string;
  avgBrewTime: number;
  avgTasteScore: number;
  coffeesUsedCount: number;
  bestBrews: string;
  problemsObserved: string;
}

export interface CommunityRecipe {
  id: string;
  coffeeName: string;
  roasterName: string;
  author: string;
  method: BrewMethod;
  description: string;
  likes: number;
  parameters: Partial<BrewLog>;
}

import React, { useState } from 'react';
import { BrewMethod, CoffeeBean, BrewLog } from '../types';

interface BrewFormProps {
  coffee: CoffeeBean;
  onSave: (log: Partial<BrewLog>) => void;
  onCancel: () => void;
}

const BrewForm: React.FC<BrewFormProps> = ({ coffee, onSave, onCancel }) => {
  const [method, setMethod] = useState<BrewMethod>(BrewMethod.ESPRESSO);
  const [baristaName, setBaristaName] = useState('');
  const [site, setSite] = useState('');
  const [machine, setMachine] = useState('');

  // Shared
  const [dose, setDose] = useState(15);
  const [yieldVal, setYieldVal] = useState(250);
  const [time, setTime] = useState(120);
  const [grinder, setGrinder] = useState('');
  const [setting, setSetting] = useState('');
  const [temp, setTemp] = useState(93);
  const [rating, setRating] = useState(4);
  const [notes, setNotes] = useState('');

  // Espresso
  const [pressure, setPressure] = useState(9);
  const [shotResult, setShotResult] = useState<'Pass' | 'Fail'>('Pass');

  // AeroPress
  const [apModel, setApModel] = useState('Standard');
  const [apMethod, setApMethod] = useState('Standard');
  const [bloomTime, setBloomTime] = useState(30);
  const [steepTime, setSteepTime] = useState(60);
  const [agitation, setAgitation] = useState('yes');

  // Filter
  const [filterBrewer, setFilterBrewer] = useState('V60');
  const [pourStructure, setPourStructure] = useState('3 Pulses');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSave({
      coffeeId: coffee.id,
      baristaName,
      site,
      machine: method === BrewMethod.ESPRESSO ? machine : undefined,
      date: new Date().toISOString(),
      method,
      dose,
      yield: yieldVal,
      brewTime: time,
      pressure: method === BrewMethod.ESPRESSO ? pressure : undefined,
      shotResult: method === BrewMethod.ESPRESSO ? shotResult : undefined,
      grinder,
      grindSetting: setting,
      aeroPressModel: method === BrewMethod.AEROPRESS ? apModel : undefined,
      aeroMethod: method === BrewMethod.AEROPRESS ? apMethod : undefined,
      bloomTime: (method === BrewMethod.AEROPRESS || method === BrewMethod.POUR_OVER) ? bloomTime : undefined,
      steepTime: method === BrewMethod.AEROPRESS ? steepTime : undefined,
      agitation: method === BrewMethod.AEROPRESS ? agitation : undefined,
      brewer: method === BrewMethod.POUR_OVER ? filterBrewer : undefined,
      pourStructure: method === BrewMethod.POUR_OVER ? pourStructure : undefined,
      water: { type: 'Filtered', temp },
      rating,
      tastingNotes: notes.split(',').map(n => n.trim()).filter(n => n !== ''),
    });
  };

  const ratio = dose > 0 ? `1:${(yieldVal / dose).toFixed(1)}` : '0';

  return (
    <form onSubmit={handleSubmit} className="space-y-5 bg-white p-6 rounded-2xl shadow-xl border border-stone-200 max-w-lg mx-auto max-h-[90vh] overflow-y-auto">
      <div className="flex justify-between items-center mb-2">
        <h2 className="text-2xl font-bold display-font">Log Brew Activity</h2>
        <button type="button" onClick={onCancel} className="text-stone-400 hover:text-stone-600">✕</button>
      </div>

      <div className="space-y-4">
        <div className="grid grid-cols-2 gap-4">
          <div>
            <label className="block text-[10px] font-bold text-stone-400 uppercase tracking-widest mb-1">Barista Name</label>
            <input type="text" value={baristaName} onChange={e => setBaristaName(e.target.value)} className="w-full bg-stone-50 border border-stone-200 rounded-lg p-2.5 text-sm" placeholder="Your Name" />
          </div>
          <div>
            <label className="block text-[10px] font-bold text-stone-400 uppercase tracking-widest mb-1">Brew Method</label>
            <select 
              value={method} 
              onChange={(e) => setMethod(e.target.value as BrewMethod)}
              className="w-full bg-stone-50 border border-stone-200 rounded-lg p-2.5 text-sm outline-none focus:ring-2 focus:ring-amber-500 font-bold text-amber-900"
            >
              {Object.values(BrewMethod).map(m => <option key={m} value={m}>{m}</option>)}
            </select>
          </div>
        </div>

        {/* Dynamic Fields Based on Method */}
        {method === BrewMethod.ESPRESSO && (
          <div className="grid grid-cols-2 gap-4 animate-in fade-in slide-in-from-top-2">
             <div>
              <label className="block text-[10px] font-bold text-stone-400 uppercase tracking-widest mb-1">Machine</label>
              <input type="text" value={machine} onChange={e => setMachine(e.target.value)} className="w-full bg-stone-50 border border-stone-200 rounded-lg p-2.5 text-sm" placeholder="Lineas PB" />
            </div>
            <div>
              <label className="block text-[10px] font-bold text-stone-400 uppercase tracking-widest mb-1">Site</label>
              <input type="text" value={site} onChange={e => setSite(e.target.value)} className="w-full bg-stone-50 border border-stone-200 rounded-lg p-2.5 text-sm" placeholder="Training Bar" />
            </div>
          </div>
        )}

        {method === BrewMethod.AEROPRESS && (
          <div className="grid grid-cols-2 gap-4 animate-in fade-in slide-in-from-top-2">
            <div>
              <label className="block text-[10px] font-bold text-stone-400 uppercase tracking-widest mb-1">Model</label>
              <select value={apModel} onChange={e => setApModel(e.target.value)} className="w-full bg-stone-50 border border-stone-200 rounded-lg p-2.5 text-sm">
                <option>Standard</option>
                <option>Go</option>
                <option>Clear</option>
                <option>XL</option>
              </select>
            </div>
            <div>
              <label className="block text-[10px] font-bold text-stone-400 uppercase tracking-widest mb-1">Agitation</label>
              <select value={agitation} onChange={e => setAgitation(e.target.value)} className="w-full bg-stone-50 border border-stone-200 rounded-lg p-2.5 text-sm">
                <option value="yes">Yes</option>
                <option value="no">No</option>
              </select>
            </div>
          </div>
        )}

        {method === BrewMethod.POUR_OVER && (
          <div className="grid grid-cols-2 gap-4 animate-in fade-in slide-in-from-top-2">
            <div>
              <label className="block text-[10px] font-bold text-stone-400 uppercase tracking-widest mb-1">Brewer</label>
              <input type="text" value={filterBrewer} onChange={e => setFilterBrewer(e.target.value)} className="w-full bg-stone-50 border border-stone-200 rounded-lg p-2.5 text-sm" placeholder="V60, Orea, etc." />
            </div>
            <div>
              <label className="block text-[10px] font-bold text-stone-400 uppercase tracking-widest mb-1">Pour Structure</label>
              <input type="text" value={pourStructure} onChange={e => setPourStructure(e.target.value)} className="w-full bg-stone-50 border border-stone-200 rounded-lg p-2.5 text-sm" placeholder="e.g. 50g x 5" />
            </div>
          </div>
        )}

        {/* Grind Parameters */}
        <div className="grid grid-cols-2 gap-4">
          <div>
            <label className="block text-[10px] font-bold text-stone-400 uppercase tracking-widest mb-1">Grinder</label>
            <input type="text" placeholder="Comandante C40" value={grinder} onChange={e => setGrinder(e.target.value)} className="w-full bg-stone-50 border border-stone-200 rounded-lg p-2.5 text-sm" />
          </div>
          <div>
            <label className="block text-[10px] font-bold text-stone-400 uppercase tracking-widest mb-1">Grinder Setting</label>
            <input type="text" placeholder="24 clicks" value={setting} onChange={e => setSetting(e.target.value)} className="w-full bg-stone-50 border border-stone-200 rounded-lg p-2.5 text-sm" />
          </div>
        </div>

        {/* Shared Numeric Parameters */}
        <div className="grid grid-cols-3 gap-3 p-4 bg-stone-50 rounded-xl border border-stone-100">
          <div>
            <label className="block text-[10px] font-bold text-stone-400 uppercase tracking-widest mb-1">Dose (g)</label>
            <input type="number" step="0.1" value={dose} onChange={e => setDose(Number(e.target.value))} className="w-full bg-white border border-stone-200 rounded-lg p-2 text-center text-sm font-bold" />
          </div>
          <div>
            <label className="block text-[10px] font-bold text-stone-400 uppercase tracking-widest mb-1">{method === BrewMethod.ESPRESSO ? 'Yield' : 'Water'} (g)</label>
            <input type="number" step="1" value={yieldVal} onChange={e => setYieldVal(Number(e.target.value))} className="w-full bg-white border border-stone-200 rounded-lg p-2 text-center text-sm font-bold" />
          </div>
          <div>
            <label className="block text-[10px] font-bold text-stone-400 uppercase tracking-widest mb-1">Temp (°C)</label>
            <input type="number" value={temp} onChange={e => setTemp(Number(e.target.value))} className="w-full bg-white border border-stone-200 rounded-lg p-2 text-center text-sm font-bold" />
          </div>
        </div>

        <div className="flex justify-center py-1">
          <span className="text-[10px] font-black text-amber-800 bg-amber-100 px-3 py-1 rounded-full uppercase tracking-tighter">
            Target Ratio: {ratio}
          </span>
        </div>

        {/* Extra Timings */}
        {(method === BrewMethod.AEROPRESS || method === BrewMethod.POUR_OVER) && (
          <div className="grid grid-cols-2 gap-4">
             <div>
              <label className="block text-[10px] font-bold text-stone-400 uppercase tracking-widest mb-1">Bloom Time (s)</label>
              <input type="number" value={bloomTime} onChange={e => setBloomTime(Number(e.target.value))} className="w-full bg-stone-50 border border-stone-200 rounded-lg p-2.5 text-sm" />
            </div>
            {method === BrewMethod.AEROPRESS && (
              <div>
                <label className="block text-[10px] font-bold text-stone-400 uppercase tracking-widest mb-1">Steep Time (s)</label>
                <input type="number" value={steepTime} onChange={e => setSteepTime(Number(e.target.value))} className="w-full bg-stone-50 border border-stone-200 rounded-lg p-2.5 text-sm" />
              </div>
            )}
            <div>
              <label className="block text-[10px] font-bold text-stone-400 uppercase tracking-widest mb-1">Total Time (s)</label>
              <input type="number" value={time} onChange={e => setTime(Number(e.target.value))} className="w-full bg-stone-50 border border-stone-200 rounded-lg p-2.5 text-sm" />
            </div>
          </div>
        )}

        {/* Espresso Calibration specifics */}
        {method === BrewMethod.ESPRESSO && (
          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-[10px] font-bold text-amber-800 uppercase tracking-widest mb-1">Pressure (bar)</label>
              <input type="number" step="0.5" value={pressure} onChange={e => setPressure(Number(e.target.value))} className="w-full bg-stone-50 border border-stone-200 rounded-lg p-2.5 text-sm" />
            </div>
            <div>
              <label className="block text-[10px] font-bold text-amber-800 uppercase tracking-widest mb-1">Shot Result</label>
              <div className="flex bg-white rounded-lg border border-amber-200 overflow-hidden">
                <button type="button" onClick={() => setShotResult('Pass')} className={`flex-1 py-2 text-xs font-bold ${shotResult === 'Pass' ? 'bg-green-600 text-white' : 'text-stone-400'}`}>Pass</button>
                <button type="button" onClick={() => setShotResult('Fail')} className={`flex-1 py-2 text-xs font-bold ${shotResult === 'Fail' ? 'bg-red-600 text-white' : 'text-stone-400'}`}>Fail</button>
              </div>
            </div>
          </div>
        )}

        <div>
          <label className="block text-[10px] font-bold text-stone-400 uppercase tracking-widest mb-1">Taste Notes & Observations</label>
          <textarea value={notes} onChange={e => setNotes(e.target.value)} className="w-full bg-stone-50 border border-stone-200 rounded-lg p-2.5 text-sm h-16" placeholder="e.g. High acidity, sweet finish..."></textarea>
        </div>

        <div className="flex items-center justify-between border-t border-stone-100 pt-3">
          <label className="text-[10px] font-bold text-stone-400 uppercase tracking-widest">Final Score</label>
          <div className="flex gap-1">
            {[1,2,3,4,5].map(star => (
              <button key={star} type="button" onClick={() => setRating(star)} className={`p-1 ${rating >= star ? 'text-amber-500' : 'text-stone-300'}`}>
                <svg className="w-6 h-6 fill-current" viewBox="0 0 20 20"><path d="M9.049 2.927c.3-.921 1.603-.921 1.902 0l1.07 3.292a1 1 0 00.95.69h3.462c.969 0 1.371 1.24.588 1.81l-2.8 2.034a1 1 0 00-.364 1.118l1.07 3.292c.3.921-.755 1.688-1.54 1.118l-2.8-2.034a1 1 0 00-1.175 0l-2.8 2.034c-.784.57-1.838-.197-1.539-1.118l1.07-3.292a1 1 0 00-.364-1.118L2.98 8.72c-.783-.57-.38-1.81.588-1.81h3.461a1 1 0 00.951-.69l1.07-3.292z" /></svg>
              </button>
            ))}
          </div>
        </div>
      </div>

      <div className="flex gap-4 pt-4 sticky bottom-0 bg-white">
        <button type="button" onClick={onCancel} className="flex-1 py-3 px-4 bg-stone-100 text-stone-600 rounded-xl font-bold hover:bg-stone-200">Cancel</button>
        <button type="submit" className="flex-1 py-3 px-4 bg-amber-800 text-white rounded-xl font-bold hover:bg-amber-900 shadow-lg shadow-amber-900/20">Log Entry</button>
      </div>
    </form>
  );
};

export default BrewForm;

export enum BrewMethod {
  ESPRESSO = 'Espresso',
  POUR_OVER = 'Filter/Pour Over',
  AEROPRESS = 'AeroPress',
  FRENCH_PRESS = 'French Press'
}

export enum RoastLevel {
  LIGHT = 'Light',
  MEDIUM_LIGHT = 'Medium-Light',
  MEDIUM = 'Medium',
  MEDIUM_DARK = 'Medium-Dark',
  DARK = 'Dark'
}

export interface CoffeeBean {
  id: string;
  name: string;
  roaster: string;
  origin: string;
  process: string;
  varietal?: string;
  roastLevel: RoastLevel;
  roastDate?: string;
  purchaseDate: string;
  remainingWeight: number;
  totalWeight: number;
  notes: string;
}

export interface WaterDetails {
  type: string;
  temp: number;
  tds?: number;
}

export interface BrewLog {
  id: string;
  coffeeId: string;
  baristaName?: string;
  site?: string;
  date: string;
  method: BrewMethod;
  grinder: string;
  grindSetting: string;
  dose: number; 
  yield: number;
  brewTime: number; 
  rating: number; 
  tastingNotes: string[];

  // Espresso Specific
  pressure?: number;
  shotResult?: 'Pass' | 'Fail';
  machine?: string;

  // AeroPress & French Press Specific
  aeroPressModel?: string;
  aeroMethod?: string; 
  bloomTime?: number;
  steepTime?: number; // Used for AeroPress and French Press immersion
  agitation?: string; 

  // Filter Specific
  brewer?: string; // V60, Chemex etc specified here
  ratio?: string;
  pourStructure?: string; 
  waterDetails?: WaterDetails;
}

export interface WeeklySummary {
  id: string;
  name: string;
  weekStartDate: string;
  weekEndDate: string;
  primaryGrinder: string;
  primaryBrewer: string;
  totalBrews: number;
  avgDose: number;
  avgRatio: string;
  avgBrewTime: number;
  avgTasteScore: number;
  coffeesUsedCount: number;
  bestBrews: string;
  problemsObserved: string;
}

import React, { useState } from 'react';
import { BrewMethod, CoffeeBean, BrewLog } from '../types';

interface BrewFormProps {
  coffee: CoffeeBean;
  onSave: (log: Partial<BrewLog>) => void;
  onCancel: () => void;
}

const BrewForm: React.FC<BrewFormProps> = ({ coffee, onSave, onCancel }) => {
  const [method, setMethod] = useState<BrewMethod>(BrewMethod.ESPRESSO);
  const [baristaName, setBaristaName] = useState('');
  const [site, setSite] = useState('');
  const [machine, setMachine] = useState('');

  // Shared
  const [dose, setDose] = useState(15);
  const [yieldVal, setYieldVal] = useState(250);
  const [time, setTime] = useState(120);
  const [grinder, setGrinder] = useState('');
  const [setting, setSetting] = useState('');
  const [temp, setTemp] = useState(93);
  const [rating, setRating] = useState(4);
  const [notes, setNotes] = useState('');

  // Espresso
  const [pressure, setPressure] = useState(9);
  const [shotResult, setShotResult] = useState<'Pass' | 'Fail'>('Pass');

  // AeroPress
  const [apModel, setApModel] = useState('Standard');
  const [apMethod, setApMethod] = useState('Standard');
  const [bloomTime, setBloomTime] = useState(30);
  const [steepTime, setSteepTime] = useState(60);
  const [agitation, setAgitation] = useState('yes');

  // Filter / Pour Over
  const [filterBrewer, setFilterBrewer] = useState('V60');
  const [pourStructure, setPourStructure] = useState('3 Pulses');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSave({
      coffeeId: coffee.id,
      baristaName,
      site,
      machine: method === BrewMethod.ESPRESSO ? machine : undefined,
      date: new Date().toISOString(),
      method,
      dose,
      yield: yieldVal,
      brewTime: time,
      pressure: method === BrewMethod.ESPRESSO ? pressure : undefined,
      shotResult: method === BrewMethod.ESPRESSO ? shotResult : undefined,
      grinder,
      grindSetting: setting,
      aeroPressModel: method === BrewMethod.AEROPRESS ? apModel : undefined,
      aeroMethod: method === BrewMethod.AEROPRESS ? apMethod : undefined,
      bloomTime: (method === BrewMethod.AEROPRESS || method === BrewMethod.POUR_OVER) ? bloomTime : undefined,
      steepTime: (method === BrewMethod.AEROPRESS || method === BrewMethod.FRENCH_PRESS) ? steepTime : undefined,
      agitation: (method === BrewMethod.AEROPRESS || method === BrewMethod.FRENCH_PRESS) ? agitation : undefined,
      brewer: method === BrewMethod.POUR_OVER ? filterBrewer : undefined,
      pourStructure: method === BrewMethod.POUR_OVER ? pourStructure : undefined,
      water: { type: 'Filtered', temp },
      rating,
      tastingNotes: notes.split(',').map(n => n.trim()).filter(n => n !== ''),
    });
  };

  const ratio = dose > 0 ? `1:${(yieldVal / dose).toFixed(1)}` : '0';

  return (
    <form onSubmit={handleSubmit} className="space-y-5 bg-white p-6 rounded-2xl shadow-xl border border-stone-200 max-w-lg mx-auto max-h-[90vh] overflow-y-auto">
      <div className="flex justify-between items-center mb-2">
        <h2 className="text-2xl font-bold display-font">Log Brew Activity</h2>
        <button type="button" onClick={onCancel} className="text-stone-400 hover:text-stone-600">✕</button>
      </div>

      <div className="space-y-4">
        <div className="grid grid-cols-2 gap-4">
          <div>
            <label className="block text-[10px] font-bold text-stone-400 uppercase tracking-widest mb-1">Barista Name</label>
            <input type="text" value={baristaName} onChange={e => setBaristaName(e.target.value)} className="w-full bg-stone-50 border border-stone-200 rounded-lg p-2.5 text-sm" placeholder="Your Name" />
          </div>
          <div>
            <label className="block text-[10px] font-bold text-stone-400 uppercase tracking-widest mb-1">Brew Method</label>
            <select 
              value={method} 
              onChange={(e) => setMethod(e.target.value as BrewMethod)}
              className="w-full bg-stone-50 border border-stone-200 rounded-lg p-2.5 text-sm outline-none focus:ring-2 focus:ring-amber-500 font-bold text-amber-900"
            >
              {Object.values(BrewMethod).map(m => <option key={m} value={m}>{m}</option>)}
            </select>
          </div>
        </div>

        {method === BrewMethod.POUR_OVER && (
          <div className="grid grid-cols-2 gap-4 animate-in fade-in slide-in-from-top-2">
            <div>
              <label className="block text-[10px] font-bold text-stone-400 uppercase tracking-widest mb-1">Specific Brewer</label>
              <select value={filterBrewer} onChange={e => setFilterBrewer(e.target.value)} className="w-full bg-stone-50 border border-stone-200 rounded-lg p-2.5 text-sm">
                <option>V60</option>
                <option>Chemex</option>
                <option>Kalita Wave</option>
                <option>Origami</option>
                <option>Orea</option>
                <option>Hario Switch</option>
              </select>
            </div>
            <div>
              <label className="block text-[10px] font-bold text-stone-400 uppercase tracking-widest mb-1">Pour Structure</label>
              <input type="text" value={pourStructure} onChange={e => setPourStructure(e.target.value)} className="w-full bg-stone-50 border border-stone-200 rounded-lg p-2.5 text-sm" placeholder="e.g. 50g x 5" />
            </div>
          </div>
        )}

        {method === BrewMethod.FRENCH_PRESS && (
          <div className="grid grid-cols-2 gap-4 animate-in fade-in slide-in-from-top-2">
            <div>
              <label className="block text-[10px] font-bold text-stone-400 uppercase tracking-widest mb-1">Immersion/Steep (s)</label>
              <input type="number" value={steepTime} onChange={e => setSteepTime(Number(e.target.value))} className="w-full bg-stone-50 border border-stone-200 rounded-lg p-2.5 text-sm" placeholder="240" />
            </div>
            <div>
              <label className="block text-[10px] font-bold text-stone-400 uppercase tracking-widest mb-1">Agitation</label>
              <select value={agitation} onChange={e => setAgitation(e.target.value)} className="w-full bg-stone-50 border border-stone-200 rounded-lg p-2.5 text-sm">
                <option value="none">None</option>
                <option value="bloom-stir">Bloom Stir</option>
                <option value="gentle">Gentle</option>
                <option value="vigorous">Vigorous</option>
              </select>
            </div>
          </div>
        )}

        <div className="grid grid-cols-2 gap-4">
          <div>
            <label className="block text-[10px] font-bold text-stone-400 uppercase tracking-widest mb-1">Grinder</label>
            <input type="text" placeholder="Comandante C40" value={grinder} onChange={e => setGrinder(e.target.value)} className="w-full bg-stone-50 border border-stone-200 rounded-lg p-2.5 text-sm" />
          </div>
          <div>
            <label className="block text-[10px] font-bold text-stone-400 uppercase tracking-widest mb-1">Grinder Setting</label>
            <input type="text" placeholder="24 clicks" value={setting} onChange={e => setSetting(e.target.value)} className="w-full bg-stone-50 border border-stone-200 rounded-lg p-2.5 text-sm" />
          </div>
        </div>

        <div className="grid grid-cols-3 gap-3 p-4 bg-stone-50 rounded-xl border border-stone-100">
          <div>
            <label className="block text-[10px] font-bold text-stone-400 uppercase tracking-widest mb-1">Dose (g)</label>
            <input type="number" step="0.1" value={dose} onChange={e => setDose(Number(e.target.value))} className="w-full bg-white border border-stone-200 rounded-lg p-2 text-center text-sm font-bold" />
          </div>
          <div>
            <label className="block text-[10px] font-bold text-stone-400 uppercase tracking-widest mb-1">{method === BrewMethod.ESPRESSO ? 'Yield' : 'Water'} (g)</label>
            <input type="number" step="1" value={yieldVal} onChange={e => setYieldVal(Number(e.target.value))} className="w-full bg-white border border-stone-200 rounded-lg p-2 text-center text-sm font-bold" />
          </div>
          <div>
            <label className="block text-[10px] font-bold text-stone-400 uppercase tracking-widest mb-1">Temp (°C)</label>
            <input type="number" value={temp} onChange={e => setTemp(Number(e.target.value))} className="w-full bg-white border border-stone-200 rounded-lg p-2 text-center text-sm font-bold" />
          </div>
        </div>

        <div className="flex justify-center py-1">
          <span className="text-[10px] font-black text-amber-800 bg-amber-100 px-3 py-1 rounded-full uppercase tracking-tighter">
            Target Ratio: {ratio}
          </span>
        </div>

        <div className="grid grid-cols-2 gap-4">
          <div>
            <label className="block text-[10px] font-bold text-stone-400 uppercase tracking-widest mb-1">Total Time (s)</label>
            <input type="number" value={time} onChange={e => setTime(Number(e.target.value))} className="w-full bg-stone-50 border border-stone-200 rounded-lg p-2.5 text-sm" />
          </div>
          {method === BrewMethod.POUR_OVER && (
            <div>
              <label className="block text-[10px] font-bold text-stone-400 uppercase tracking-widest mb-1">Bloom Time (s)</label>
              <input type="number" value={bloomTime} onChange={e => setBloomTime(Number(e.target.value))} className="w-full bg-stone-50 border border-stone-200 rounded-lg p-2.5 text-sm" />
            </div>
          )}
        </div>

        <div>
          <label className="block text-[10px] font-bold text-stone-400 uppercase tracking-widest mb-1">Taste Notes & Observations</label>
          <textarea value={notes} onChange={e => setNotes(e.target.value)} className="w-full bg-stone-50 border border-stone-200 rounded-lg p-2.5 text-sm h-16" placeholder="e.g. Sweet, balanced, light acidity..."></textarea>
        </div>

        <div className="flex items-center justify-between border-t border-stone-100 pt-3">
          <label className="text-[10px] font-bold text-stone-400 uppercase tracking-widest">Final Score</label>
          <div className="flex gap-1">
            {[1,2,3,4,5].map(star => (
              <button key={star} type="button" onClick={() => setRating(star)} className={`p-1 ${rating >= star ? 'text-amber-500' : 'text-stone-300'}`}>
                <svg className="w-6 h-6 fill-current" viewBox="0 0 20 20"><path d="M9.049 2.927c.3-.921 1.603-.921 1.902 0l1.07 3.292a1 1 0 00.95.69h3.462c.969 0 1.371 1.24.588 1.81l-2.8 2.034a1 1 0 00-.364 1.118l1.07 3.292c.3.921-.755 1.688-1.54 1.118l-2.8-2.034a1 1 0 00-1.175 0l-2.8 2.034c-.784.57-1.838-.197-1.539-1.118l1.07-3.292a1 1 0 00-.364-1.118L2.98 8.72c-.783-.57-.38-1.81.588-1.81h3.461a1 1 0 00.951-.69l1.07-3.292z" /></svg>
              </button>
            ))}
          </div>
        </div>
      </div>

      <div className="flex gap-4 pt-4 sticky bottom-0 bg-white">
        <button type="button" onClick={onCancel} className="flex-1 py-3 px-4 bg-stone-100 text-stone-600 rounded-xl font-bold hover:bg-stone-200">Cancel</button>
        <button type="submit" className="flex-1 py-3 px-4 bg-amber-800 text-white rounded-xl font-bold hover:bg-amber-900 shadow-lg shadow-amber-900/20">Log Entry</button>
      </div>
    </form>
  );
};

