  const [activeTab, setActiveTab] = useState<'weekly' | 'journal' | 'library' | 'community' | 'grind'>('weekly');
  const [selectedCoffee, setSelectedCoffee] = useState<CoffeeBean | null>(null);
  const [showBrewForm, setShowBrewForm] = useState(false);
  const [showBeanForm, setShowBeanForm] = useState(false);
  const [aiAdvice, setAiAdvice] = useState<any>(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [communityRecipes, setCommunityRecipes] = useState<any[]>([]);
  const [isLoading, setIsLoading] = useState(false);

  const handleAddBrew = (log: Partial<BrewLog>) => {
    const newLog = { ...log, id: Math.random().toString(36).substr(2, 9) } as BrewLog;
    setBrewLogs([newLog, ...brewLogs]);
    setCoffees(prev => prev.map(c => 
      c.id === log.coffeeId ? { ...c, remainingWeight: Math.max(0, c.remainingWeight - (log.dose || 0)) } : c
    ));
    setShowBrewForm(false);
    setSelectedCoffee(null);
  };

  const handleAddBean = (bean: CoffeeBean) => {
    setCoffees(prev => [bean, ...prev]);
    setShowBeanForm(false);
  };

  const handleFetchAdvice = async (coffee: CoffeeBean) => {
    setIsLoading(true);
    const advice = await getBrewAdvice(coffee, BrewMethod.POUR_OVER);
    setAiAdvice(advice);
    setIsLoading(false);
  };

  const handleSearchCommunity = async () => {
    setIsLoading(true);
    const results = await searchCommunityRecipes(searchQuery);
    setCommunityRecipes(results);
    setIsLoading(false);
  };

