      <header className="bg-white border-b border-stone-100 sticky top-0 z-30 px-6 py-4 flex justify-between items-center shadow-sm">
        <h1 className="text-2xl font-bold display-font text-stone-800">Barista <span className="text-amber-800">Journal</span></h1>
        <div className="flex items-center gap-3">
          <button 
            onClick={() => setActiveTab('grind')}
