          >
             <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 6V4m0 2a2 2 0 100 4m0-4a2 2 0 110 4m-6 8a2 2 0 100-4m0 4a2 2 0 110-4m0 4v2m0-6V4m6 6v10m6-2a2 2 0 100-4m0 4a2 2 0 110-4m0 4v2m0-6V4"/></svg>
          </button>
          <div className="w-8 h-8 rounded-full bg-stone-100 border border-stone-200 overflow-hidden ring-2 ring-white shadow-sm">
            <img src="https://picsum.photos/100/100" alt="Avatar" />
          </div>
        </div>
      </header>

      <main className="flex-1 max-w-4xl mx-auto w-full p-6">
        {activeTab === 'weekly' && (
          <div className="animate-in fade-in slide-in-from-bottom-4 duration-500">
             <div className="flex justify-between items-center mb-6">
              <h2 className="text-xl font-bold text-stone-800">Weekly Summaries</h2>
              <button className="bg-amber-800 text-white p-2 px-4 rounded-xl flex items-center gap-2 text-xs font-black uppercase tracking-widest shadow-lg shadow-amber-900/20">
                <Icons.Plus className="w-4 h-4" /> New Week
              </button>
            </div>
            <div className="space-y-6">
              {weeklySummaries.map(sum => (
                <div key={sum.id} className="bg-white rounded-3xl border border-stone-100 overflow-hidden shadow-sm hover:shadow-xl transition-all">
                  <div className="bg-stone-900 p-8 text-white">
                    <div className="flex justify-between items-start">
                      <div>
                        <p className="text-[10px] font-black text-stone-500 uppercase tracking-widest mb-1">Calibration Records</p>
                        <h3 className="text-3xl font-bold display-font">Week of {new Date(sum.weekStartDate).toLocaleDateString()}</h3>
                        <p className="text-stone-400 text-xs mt-1 font-medium tracking-wide">Configuration: {sum.primaryGrinder} / {sum.primaryBrewer}</p>
                      </div>
                    </div>
                  </div>
                  <div className="p-8">
                    <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-8">
                      {[
                        { label: 'Brews', val: sum.totalBrews },
                        { label: 'Avg Dose', val: sum.avgDose + 'g' },
                        { label: 'Ratio', val: sum.avgRatio },
                        { label: 'Taste', val: sum.avgTasteScore + '/5' }
                      ].map((stat, i) => (
                        <div key={i} className="bg-stone-50 p-4 rounded-2xl text-center border border-stone-100">
                          <p className="text-[10px] font-bold text-stone-400 uppercase mb-1">{stat.label}</p>
                          <p className="text-2xl font-black text-amber-900">{stat.val}</p>
                        </div>
                      ))}
                    </div>
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4 pt-6 border-t border-stone-100">
                      <div className="bg-amber-50/50 p-5 rounded-2xl border border-amber-100">
                        <h4 className="text-[10px] font-black text-amber-900 uppercase tracking-widest mb-2 flex items-center gap-2"><Icons.Star className="w-3 h-3 fill-current" /> High Points</h4>
                        <p className="text-sm text-stone-700 leading-relaxed font-medium">{sum.bestBrews}</p>
                      </div>
                      <div className="bg-stone-50 p-5 rounded-2xl border border-stone-200">
                        <h4 className="text-[10px] font-black text-stone-500 uppercase tracking-widest mb-2 flex items-center gap-2">⚠️ Field Notes</h4>
                        <p className="text-sm text-stone-600 leading-relaxed font-medium">{sum.problemsObserved}</p>
                      </div>
                    </div>
                  </div>
                </div>
              ))}
