          <div className="animate-in fade-in slide-in-from-bottom-4 duration-500">
            <h2 className="text-xl font-bold text-stone-800 mb-6">Extraction Journal</h2>
            {brewLogs.length === 0 ? (
              <div className="text-center py-24 bg-white rounded-3xl border border-dashed border-stone-200">
                <Icons.Coffee className="w-16 h-16 text-stone-100 mx-auto mb-4" />
                <p className="text-stone-400 font-bold uppercase text-[10px] tracking-widest">No entries found</p>
              </div>
            ) : (
              <div className="space-y-4">
                {brewLogs.map(log => {
                  const coffee = coffees.find(c => c.id === log.coffeeId);
                  const ratio = log.dose > 0 ? `1:${(log.yield / log.dose).toFixed(1)}` : '-';
                  return (
                    <div key={log.id} className="bg-white p-6 rounded-3xl shadow-sm border border-stone-100 relative group hover:border-amber-300 transition-all">
                      <div className="flex justify-between mb-4">
                        <div>
                          <p className="text-[10px] uppercase font-black text-amber-800 mb-1">{log.method} • {log.baristaName || 'Barista'}</p>
                          <h3 className="font-bold text-xl text-stone-800">{coffee?.name}</h3>
                          <p className="text-xs text-stone-500 font-bold tracking-tight">{log.site} {log.machine ? `• ${log.machine}` : ''}</p>
                        </div>
                        <div className="text-right">
                          <p className="text-xs text-stone-400 font-black">{new Date(log.date).toLocaleDateString()}</p>
                          <div className="flex gap-0.5 text-amber-500 mt-1">
