                          { l: 'Dose', v: log.dose+'g' },
                          { l: 'Water', v: log.yield+'g' },
                          { l: 'Ratio', v: ratio },
                          { l: 'Time', v: log.brewTime+'s' },
                          { l: 'Grind', v: log.grinder, t: true },
                          { l: 'Set', v: log.grindSetting }
                        ].map((s, i) => (
                          <div key={i} className="text-[10px]">
                            <p className="text-stone-400 font-black uppercase mb-0.5">{s.l}</p>
                            <p className={`font-black text-stone-800 ${s.t ? 'truncate px-1' : ''}`}>{s.v}</p>
                          </div>
                        ))}
                      </div>
                    </div>
                  );
                })}
              </div>
            )}
          </div>
        )}

        {activeTab === 'library' && (
          <div className="animate-in fade-in slide-in-from-bottom-4 duration-500">
            <div className="flex justify-between items-center mb-6">
              <h2 className="text-xl font-bold text-stone-800">Bean Inventory</h2>
