            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              {coffees.map(coffee => (
                <CoffeeCard key={coffee.id} coffee={coffee} onClick={(c) => setSelectedCoffee(c)} />
              ))}
            </div>

            {selectedCoffee && !showBrewForm && (
              <div className="fixed inset-0 bg-black/60 backdrop-blur-sm flex items-center justify-center z-50 p-6 overflow-y-auto">
                <div className="bg-white rounded-[2rem] w-full max-w-2xl p-10 space-y-8 relative max-h-[90vh] overflow-y-auto shadow-2xl">
                  <button onClick={() => {setSelectedCoffee(null); setAiAdvice(null);}} className="absolute top-6 right-6 p-2 bg-stone-100 rounded-full text-stone-500 hover:text-stone-900">
                    <Icons.Plus className="w-7 h-7 rotate-45" />
                  </button>
                  <div className="flex justify-between items-start pt-4">
                    <div className="space-y-1">
                      <p className="text-amber-800 font-black uppercase tracking-[0.2em] text-[10px]">{selectedCoffee.roaster}</p>
                      <h2 className="text-5xl font-bold display-font text-stone-800 leading-tight">{selectedCoffee.name}</h2>
                      <p className="text-stone-500 text-lg font-medium">{selectedCoffee.origin} • {selectedCoffee.process}</p>
                    </div>
                  </div>

                  {/* Terroir Detail Grid */}
                  <div className="grid grid-cols-2 gap-6 p-6 bg-stone-50 rounded-3xl border border-stone-100">
                    <div>
                      <p className="text-[10px] font-black text-stone-400 uppercase tracking-widest mb-1">Terroir & Altitude</p>
                      <p className="text-sm font-bold text-stone-700">{selectedCoffee.altitude || 'Unknown Altitude'}</p>
                      <p className="text-xs text-stone-500 mt-1">{selectedCoffee.varietal} varietal</p>
                    </div>
                    <div>
                      <p className="text-[10px] font-black text-stone-400 uppercase tracking-widest mb-1">Estate / Farm</p>
                      <p className="text-sm font-bold text-stone-700">{selectedCoffee.farm || 'Multiple Producers'}</p>
                      <p className="text-xs text-stone-500 mt-1">{selectedCoffee.region}</p>
                    </div>
                  </div>

                  {selectedCoffee.bagTastingNotes && (
                    <div className="flex flex-wrap gap-2">
                      {selectedCoffee.bagTastingNotes.map(note => (
                        <span key={note} className="px-4 py-1.5 bg-amber-50 text-amber-900 rounded-full text-xs font-black uppercase tracking-tighter border border-amber-100">
                          {note}
                        </span>
                      ))}
                    </div>
                  )}

                  <div className="flex gap-4 pt-4">
                    <button onClick={() => setShowBrewForm(true)} className="flex-1 bg-amber-800 text-white py-5 rounded-2xl font-black uppercase text-xs tracking-widest flex items-center justify-center gap-3 hover:bg-amber-900 shadow-xl shadow-amber-900/20 active:scale-[0.98] transition-all">
                      <Icons.Coffee className="w-5 h-5" /> New Calibration
                    </button>
                    <button onClick={() => handleFetchAdvice(selectedCoffee)} className="flex-1 bg-stone-900 text-white py-5 rounded-2xl font-black uppercase text-xs tracking-widest flex items-center justify-center gap-3 hover:bg-black transition-all">
                      {isLoading ? "Consulting AI..." : "Smart Recipe"}
                    </button>
                  </div>
                </div>
              </div>
            )}
          </div>
        )}

        {activeTab === 'community' && (
          <div className="animate-in fade-in slide-in-from-bottom-4 duration-500">
            <div className="bg-gradient-to-br from-amber-900 to-stone-900 rounded-[3rem] p-12 mb-10 text-white relative overflow-hidden shadow-2xl">
              <div className="relative z-10">
                <h2 className="text-4xl font-bold display-font mb-3">Community Hub</h2>
                <p className="text-amber-200/80 mb-10 text-lg font-medium max-w-md">Sync recipes with enthusiasts and discover the global coffee standard.</p>
                <div className="flex gap-3 bg-white/10 p-2.5 rounded-[2.5rem] border border-white/20 backdrop-blur-xl">
                  <input type="text" placeholder="Roasters, origins, brew tools..." className="flex-1 bg-transparent px-6 py-4 text-white placeholder-white/30 outline-none font-bold" value={searchQuery} onChange={(e) => setSearchQuery(e.target.value)} />
                  <button onClick={handleSearchCommunity} disabled={isLoading} className="bg-white text-amber-900 px-10 py-4 rounded-[2rem] font-black uppercase text-xs tracking-[0.2em] hover:bg-amber-50 disabled:opacity-50 transition-all shadow-xl active:scale-95">
                    {isLoading ? "..." : "Fetch"}
                  </button>
                </div>
              </div>
              <div className="absolute -right-24 -bottom-24 opacity-10 rotate-45 scale-150">
                <Icons.Users className="w-96 h-96" />
              </div>
            </div>
          </div>
        )}

        {activeTab === 'grind' && <GrindReference />}
      </main>

      {/* MODALS */}
      {showBrewForm && selectedCoffee && (
        <div className="fixed inset-0 bg-black/80 backdrop-blur-lg flex items-center justify-center z-[70] p-6 overflow-y-auto">
          <BrewForm coffee={selectedCoffee} onSave={handleAddBrew} onCancel={() => setShowBrewForm(false)} />
        </div>
      )}

      {showBeanForm && (
        <div className="fixed inset-0 bg-black/80 backdrop-blur-lg flex items-center justify-center z-[70] p-6 overflow-y-auto">
          <CoffeeBeanForm onSave={handleAddBean} onCancel={() => setShowBeanForm(false)} />
        </div>
      )}

      {/* NAV BAR */}
      <nav className="fixed bottom-6 left-1/2 -translate-x-1/2 w-[calc(100%-3rem)] max-w-lg bg-stone-900/90 backdrop-blur-2xl border border-white/10 px-4 py-4 flex justify-around items-center z-50 rounded-[2.5rem] shadow-2xl">
        {[
          { id: 'weekly', icon: <Icons.Search className="w-6 h-6" />, label: 'Weekly' },
          { id: 'journal', icon: <Icons.Book className="w-6 h-6" />, label: 'Journal' },
          { id: 'library', icon: <Icons.Coffee className="w-6 h-6" />, label: 'Library' },
          { id: 'community', icon: <Icons.Users className="w-6 h-6" />, label: 'Social' }
        ].map(item => (
          <button 
            key={item.id}
            onClick={() => setActiveTab(item.id as any)} 
            className={`flex flex-col items-center gap-1.5 transition-all group ${activeTab === item.id ? 'text-amber-400 scale-110' : 'text-stone-500 hover:text-stone-300'}`}
          >
            <div className={`p-2.5 rounded-2xl transition-all ${activeTab === item.id ? 'bg-amber-400/10 shadow-inner' : 'group-hover:bg-white/5'}`}>
              {item.icon}
            </div>
            <span className={`text-[8px] font-black uppercase tracking-[0.25em] transition-opacity ${activeTab === item.id ? 'opacity-100' : 'opacity-40'}`}>
              {item.label}
            </span>
          </button>
        ))}
      </nav>
    </div>
  );
};

