      <nav className="fixed bottom-6 left-1/2 -translate-x-1/2 w-[calc(100%-3rem)] max-w-lg bg-stone-900/90 backdrop-blur-2xl border border-white/10 px-4 py-4 flex justify-around items-center z-50 rounded-[2.5rem] shadow-2xl">
