                        </div>
                      </div>
                      <div className="grid grid-cols-4 gap-2 bg-stone-50 p-4 rounded-2xl text-center">
                        <div className="text-[10px]"><p className="text-stone-400 font-black uppercase">Dose</p><p className="font-black text-stone-800">{log.dose}g</p></div>
                        <div className="text-[10px]"><p className="text-stone-400 font-black uppercase">Yield</p><p className="font-black text-stone-800">{log.yield}g</p></div>
                        <div className="text-[10px]"><p className="text-stone-400 font-black uppercase">Time</p><p className="font-black text-stone-800">{log.brewTime}s</p></div>
                        <div className="text-[10px]"><p className="text-stone-400 font-black uppercase">Temp</p><p className="font-black text-stone-800">{log.waterTemp}°C</p></div>
                      </div>
                    </div>
                  );
                })}
              </div>
            )}
          </div>
        )}

        {activeTab === 'library' && (
          <div className="animate-in fade-in slide-in-from-bottom-4 duration-500">
            <div className="flex justify-between items-center mb-6">
              <h2 className="text-2xl font-bold text-stone-800 display-font">Coffee Library</h2>
              <button onClick={() => setShowBeanForm(true)} className="bg-stone-900 text-white p-3 px-6 rounded-2xl flex items-center gap-2 text-xs font-black uppercase tracking-widest active:scale-95 transition-all">
                <Icons.Plus className="w-4 h-4" /> Add Bean
              </button>
            </div>
            <div className="grid grid-cols-1 gap-4">
              {coffees.map(coffee => (
                <CoffeeCard key={coffee.id} coffee={coffee} onClick={(c) => { setSelectedCoffee(c); setBrewFlowStep('brew'); setShowBrewFlow(true); }} />
              ))}
            </div>
          </div>
        )}

        {activeTab === 'grind' && <GrindReference />}
      </main>

      {/* MODALS */}
      {showBrewFlow && (
        <div className="fixed inset-0 bg-stone-900/60 backdrop-blur-md flex items-center justify-center z-[70] p-6 overflow-y-auto">
          {brewFlowStep === 'select' && (
            <div className="bg-white rounded-[2.5rem] w-full max-w-md p-8 shadow-2xl animate-in zoom-in-95">
              <div className="flex justify-between items-center mb-6">
                <h3 className="text-xl font-bold text-stone-800">Select Coffee</h3>
                <button onClick={() => setShowBrewFlow(false)} className="text-stone-400 hover:text-stone-800">✕</button>
              </div>
              <div className="space-y-3 max-h-80 overflow-y-auto mb-6 pr-2">
                {coffees.map(c => (
                  <button key={c.id} onClick={() => { setSelectedCoffee(c); setBrewFlowStep('brew'); }} className="w-full text-left p-4 rounded-2xl border border-stone-100 hover:border-amber-400 hover:bg-amber-50 transition-all flex justify-between items-center">
                    <div>
                      <p className="font-bold text-stone-800">{c.name}</p>
                      <p className="text-[10px] text-stone-400 font-black uppercase">{c.roaster}</p>
                    </div>
                    <span className="text-[10px] font-black text-stone-300">{c.remainingWeight}g left</span>
                  </button>
                ))}
              </div>
              <button 
                onClick={() => setBrewFlowStep('new-bean')}
                className="w-full py-4 border-2 border-dashed border-stone-200 text-stone-400 rounded-2xl font-bold text-sm hover:border-amber-400 hover:text-amber-800 transition-all"
              >
                + Register New Bean
              </button>
            </div>
          )}

          {brewFlowStep === 'new-bean' && (
            <CoffeeBeanForm 
              onSave={handleAddBean} 
              onCancel={() => setBrewFlowStep('select')} 
            />
          )}

          {brewFlowStep === 'brew' && selectedCoffee && (
            <BrewForm 
              coffee={selectedCoffee} 
              onSave={handleSaveBrew} 
              onCancel={() => setBrewFlowStep('select')} 
            />
          )}
        </div>
      )}

      {showBeanForm && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-md flex items-center justify-center z-[70] p-6 overflow-y-auto">
          <CoffeeBeanForm onSave={handleAddBean} onCancel={() => setShowBeanForm(false)} />
        </div>
      )}

      <nav className="fixed bottom-6 left-1/2 -translate-x-1/2 w-[calc(100%-3rem)] max-w-md bg-stone-900/90 backdrop-blur-xl border border-white/10 px-4 py-4 flex justify-around items-center z-50 rounded-[2.5rem] shadow-2xl">
        {[
          { id: 'journal', icon: <Icons.Book className="w-6 h-6" />, label: 'Journal' },
          { id: 'library', icon: <Icons.Coffee className="w-6 h-6" />, label: 'Library' },
          { id: 'grind', icon: <Icons.Search className="w-6 h-6" />, label: 'Grind' },
          { id: 'community', icon: <Icons.Users className="w-6 h-6" />, label: 'Social' }
        ].map(item => (
          <button key={item.id} onClick={() => setActiveTab(item.id as any)} className={`flex flex-col items-center gap-1.5 transition-all group ${activeTab === item.id ? 'text-amber-400' : 'text-stone-500 hover:text-stone-300'}`}>
            <div className={`p-2.5 rounded-2xl transition-all ${activeTab === item.id ? 'bg-amber-400/10' : 'group-hover:bg-white/5'}`}>{item.icon}</div>
            <span className={`text-[8px] font-black uppercase tracking-[0.2em] ${activeTab === item.id ? 'opacity-100' : 'opacity-40'}`}>{item.label}</span>
          </button>
        ))}
      </nav>
    </div>
  );
};

