import React, { useState } from 'react';
import { BrewMethod, CoffeeBean, BrewLog } from '../types';

interface BrewFormProps {
  coffee: CoffeeBean;
  onSave: (log: Partial<BrewLog>) => void;
  onCancel: () => void;
}

const BrewForm: React.FC<BrewFormProps> = ({ coffee, onSave, onCancel }) => {
  const [method, setMethod] = useState<BrewMethod>(BrewMethod.ESPRESSO);
  const [baristaName, setBaristaName] = useState('');
  const [site, setSite] = useState('');
  const [machine, setMachine] = useState('');

  // Shared
  const [dose, setDose] = useState(15);
  const [yieldVal, setYieldVal] = useState(250);
  const [time, setTime] = useState(120);
  const [grinder, setGrinder] = useState('');
  const [setting, setSetting] = useState('');
  const [temp, setTemp] = useState(93);
  const [rating, setRating] = useState(4);
  const [notes, setNotes] = useState('');
  const [processNotes, setProcessNotes] = useState('');

  // Espresso
  const [pressure, setPressure] = useState(9);
  const [shotResult, setShotResult] = useState<'Pass' | 'Fail'>('Pass');

  // AeroPress / Cold Brew / Steep methods
  const [apModel, setApModel] = useState('Standard');
  const [apMethod, setApMethod] = useState('Standard');
  const [bloomTime, setBloomTime] = useState(30);
  const [steepTime, setSteepTime] = useState(12); // Default 12 hours
  const [agitation, setAgitation] = useState('none');
  const [coldBrewType, setColdBrewType] = useState<'Concentrate' | 'Ready to Drink'>('Ready to Drink');

  // Filter / Pour Over
  const [filterBrewer, setFilterBrewer] = useState('V60');
  const [pourStructure, setPourStructure] = useState('3 Pulses');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSave({
      coffeeId: coffee.id,
      baristaName,
      site,
      machine: method === BrewMethod.ESPRESSO ? machine : undefined,
      date: new Date().toISOString(),
      method,
      dose,
      yield: yieldVal,
      brewTime: time,
      pressure: method === BrewMethod.ESPRESSO ? pressure : undefined,
      shotResult: method === BrewMethod.ESPRESSO ? shotResult : undefined,
      grinder,
      grindSetting: setting,
      aeroPressModel: method === BrewMethod.AEROPRESS ? apModel : undefined,
      aeroMethod: method === BrewMethod.AEROPRESS ? apMethod : undefined,
      bloomTime: (method === BrewMethod.AEROPRESS || method === BrewMethod.POUR_OVER || method === BrewMethod.COLD_BREW) ? bloomTime : undefined,
      steepTime: (method === BrewMethod.AEROPRESS || method === BrewMethod.FRENCH_PRESS || method === BrewMethod.COLD_BREW) ? steepTime : undefined,
      agitation: (method === BrewMethod.AEROPRESS || method === BrewMethod.FRENCH_PRESS || method === BrewMethod.COLD_BREW) ? agitation : undefined,
      brewer: method === BrewMethod.POUR_OVER ? filterBrewer : undefined,
      pourStructure: method === BrewMethod.POUR_OVER ? pourStructure : undefined,
      waterTemp: temp,
      waterType: 'Filtered',
      rating,
      tastingNotes: notes.split(',').map(n => n.trim()).filter(n => n !== ''),
      processNotes: method === BrewMethod.COLD_BREW ? processNotes : undefined,
      coldBrewType: method === BrewMethod.COLD_BREW ? coldBrewType : undefined,
    });
  };

  const ratio = dose > 0 ? `1:${(yieldVal / dose).toFixed(1)}` : '0';

  return (
    <form onSubmit={handleSubmit} className="space-y-5 bg-white p-6 rounded-[2.5rem] shadow-2xl border border-stone-100 max-w-lg mx-auto max-h-[90vh] overflow-y-auto animate-in zoom-in-95 duration-300">
      <div className="flex justify-between items-center mb-2">
        <div>
          <h2 className="text-2xl font-black display-font text-stone-800">Log Calibration</h2>
          <p className="text-[10px] font-bold text-stone-400 uppercase tracking-widest">{coffee.name}</p>
        </div>
        <button type="button" onClick={onCancel} className="p-2 bg-stone-50 rounded-full text-stone-400 hover:text-stone-800 transition-colors">✕</button>
      </div>

      <div className="space-y-4">
        <div className="grid grid-cols-2 gap-4">
          <div>
            <label className="block text-[10px] font-bold text-stone-400 uppercase tracking-widest mb-1">Barista</label>
            <input type="text" value={baristaName} onChange={e => setBaristaName(e.target.value)} className="w-full bg-stone-50 border border-stone-200 rounded-xl p-3 text-sm font-medium focus:ring-2 focus:ring-amber-500 outline-none transition-all" placeholder="Your Name" />
          </div>
          <div>
            <label className="block text-[10px] font-bold text-stone-400 uppercase tracking-widest mb-1">Method</label>
            <select 
              value={method} 
              onChange={(e) => setMethod(e.target.value as BrewMethod)}
              className="w-full bg-stone-50 border border-stone-200 rounded-xl p-3 text-sm outline-none focus:ring-2 focus:ring-amber-500 font-black text-amber-900 appearance-none"
            >
              {Object.values(BrewMethod).map(m => <option key={m} value={m}>{m}</option>)}
            </select>
          </div>
        </div>

        {method === BrewMethod.COLD_BREW && (
          <div className="space-y-4 p-5 bg-amber-50/50 rounded-2xl border border-amber-100 animate-in fade-in slide-in-from-top-2">
            <h4 className="text-[10px] font-black text-amber-800 uppercase tracking-[0.2em] mb-2">Cold Brew Process</h4>

            <div className="flex items-center gap-4 mb-2">
              <label className="flex items-center gap-2 cursor-pointer group">
                <input 
                  type="radio" 
                  name="cbType" 
                  checked={coldBrewType === 'Ready to Drink'} 
                  onChange={() => setColdBrewType('Ready to Drink')}
                  className="w-4 h-4 text-amber-800 focus:ring-amber-800 border-stone-300"
                />
                <span className="text-[10px] font-black uppercase tracking-widest text-stone-600 group-hover:text-amber-800 transition-colors">Ready to Drink</span>
              </label>
              <label className="flex items-center gap-2 cursor-pointer group">
                <input 
                  type="radio" 
                  name="cbType" 
                  checked={coldBrewType === 'Concentrate'} 
                  onChange={() => setColdBrewType('Concentrate')}
                  className="w-4 h-4 text-amber-800 focus:ring-amber-800 border-stone-300"
                />
                <span className="text-[10px] font-black uppercase tracking-widest text-stone-600 group-hover:text-amber-800 transition-colors">Concentrate</span>
              </label>
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="block text-[10px] font-bold text-stone-400 uppercase tracking-widest mb-1">Steep Time (Hrs)</label>
                <input type="number" step="0.5" value={steepTime} onChange={e => setSteepTime(Number(e.target.value))} className="w-full bg-white border border-amber-200 rounded-xl p-3 text-sm font-bold" />
              </div>
              <div>
                <label className="block text-[10px] font-bold text-stone-400 uppercase tracking-widest mb-1">Bloom (Secs)</label>
                <input type="number" value={bloomTime} onChange={e => setBloomTime(Number(e.target.value))} className="w-full bg-white border border-amber-200 rounded-xl p-3 text-sm font-bold" placeholder="0 if none" />
              </div>
            </div>
            <div>
              <label className="block text-[10px] font-bold text-stone-400 uppercase tracking-widest mb-1">Brewing Steps / Bloom Method</label>
              <textarea 
                value={processNotes} 
                onChange={e => setProcessNotes(e.target.value)} 
                className="w-full bg-white border border-amber-200 rounded-xl p-3 text-sm h-24 placeholder-stone-300"
                placeholder="e.g. Immersion for 18 hours. Room temp bloom for 45 secs with 100g water, then top up..."
              ></textarea>
            </div>
          </div>
        )}

        <div className="grid grid-cols-2 gap-4">
          <div>
            <label className="block text-[10px] font-bold text-stone-400 uppercase tracking-widest mb-1">Grinder</label>
            <input type="text" placeholder="e.g. Niche Zero" value={grinder} onChange={e => setGrinder(e.target.value)} className="w-full bg-stone-50 border border-stone-200 rounded-xl p-3 text-sm font-medium" />
          </div>
          <div>
            <label className="block text-[10px] font-bold text-stone-400 uppercase tracking-widest mb-1">Setting</label>
            <input type="text" placeholder="e.g. 45" value={setting} onChange={e => setSetting(e.target.value)} className="w-full bg-stone-50 border border-stone-200 rounded-xl p-3 text-sm font-medium" />
          </div>
        </div>

        <div className="grid grid-cols-3 gap-3 p-5 bg-stone-50 rounded-[1.5rem] border border-stone-100">
          <div>
            <label className="block text-[10px] font-black text-stone-400 uppercase tracking-widest mb-1 text-center">Dose (g)</label>
            <input type="number" step="0.1" value={dose} onChange={e => setDose(Number(e.target.value))} className="w-full bg-white border border-stone-200 rounded-xl p-3 text-center text-sm font-black text-stone-800" />
          </div>
          <div>
            <label className="block text-[10px] font-black text-stone-400 uppercase tracking-widest mb-1 text-center">Liquid (g)</label>
            <input type="number" step="1" value={yieldVal} onChange={e => setYieldVal(Number(e.target.value))} className="w-full bg-white border border-stone-200 rounded-xl p-3 text-center text-sm font-black text-stone-800" />
          </div>
          <div>
            <label className="block text-[10px] font-black text-stone-400 uppercase tracking-widest mb-1 text-center">Ratio</label>
            <div className="w-full bg-amber-100/50 border border-amber-200 rounded-xl p-3 text-center text-sm font-black text-amber-900">
              {ratio}
            </div>
          </div>
        </div>

        <div className="grid grid-cols-2 gap-4">
           <div>
            <label className="block text-[10px] font-bold text-stone-400 uppercase tracking-widest mb-1">Water Temp (°C)</label>
            <input type="number" value={temp} onChange={e => setTemp(Number(e.target.value))} className="w-full bg-stone-50 border border-stone-200 rounded-xl p-3 text-sm font-medium" />
          </div>
          {method !== BrewMethod.COLD_BREW && (
            <div>
              <label className="block text-[10px] font-bold text-stone-400 uppercase tracking-widest mb-1">Total Time (s)</label>
              <input type="number" value={time} onChange={e => setTime(Number(e.target.value))} className="w-full bg-stone-50 border border-stone-200 rounded-xl p-3 text-sm font-medium" />
            </div>
          )}
        </div>

        <div>
          <label className="block text-[10px] font-bold text-stone-400 uppercase tracking-widest mb-1">Tasting Notes</label>
          <textarea value={notes} onChange={e => setNotes(e.target.value)} className="w-full bg-stone-50 border border-stone-200 rounded-xl p-3 text-sm h-16 font-medium" placeholder="Berry, Chocolate, Silky..."></textarea>
        </div>

        <div className="flex items-center justify-between border-t border-stone-100 pt-5">
          <label className="text-[10px] font-black text-stone-400 uppercase tracking-widest">Final Rating</label>
          <div className="flex gap-1.5">
            {[1,2,3,4,5].map(star => (
              <button key={star} type="button" onClick={() => setRating(star)} className={`transition-all ${rating >= star ? 'text-amber-500 scale-110' : 'text-stone-200 hover:text-stone-300'}`}>
                <svg className="w-8 h-8 fill-current" viewBox="0 0 20 20"><path d="M9.049 2.927c.3-.921 1.603-.921 1.902 0l1.07 3.292a1 1 0 00.95.69h3.462c.969 0 1.371 1.24.588 1.81l-2.8 2.034a1 1 0 00-.364 1.118l1.07 3.292c.3.921-.755 1.688-1.54 1.118l-2.8-2.034a1 1 0 00-1.175 0l-2.8 2.034c-.784.57-1.838-.197-1.539-1.118l1.07-3.292a1 1 0 00-.364-1.118L2.98 8.72c-.783-.57-.38-1.81.588-1.81h3.461a1 1 0 00.951-.69l1.07-3.292z" /></svg>
              </button>
            ))}
          </div>
        </div>
      </div>

      <div className="flex gap-4 pt-4">
        <button type="button" onClick={onCancel} className="flex-1 py-4 bg-stone-100 text-stone-500 rounded-2xl font-black uppercase text-[10px] tracking-widest hover:bg-stone-200 transition-all">Cancel</button>
        <button type="submit" className="flex-1 py-4 bg-stone-900 text-white rounded-2xl font-black uppercase text-[10px] tracking-widest hover:bg-black transition-all shadow-xl shadow-stone-900/20 active:scale-[0.98]">Save Entry</button>
      </div>
    </form>
  );
};

