  coldBrewSystem?: string;
}

export interface WeeklySummary {
  id: string;
  name: string;
  weekStartDate: string;
  weekEndDate: string;
  primaryGrinder: string;
  primaryBrewer: string;
  totalBrews: number;
  avgDose: number;
  avgRatio: string;
