  avgTasteScore: number;
  coffeesUsedCount: number;
  bestBrews: string;
  problemsObserved: string;
}

import React, { useState } from 'react';
import { BrewMethod, CoffeeBean, BrewLog } from '../types';

const EQUIPMENT_DB = {
  GRINDERS: ['Niche Zero', 'Fellow Ode Gen 2', 'Comandante C40', 'Baratza Encore', '1Zpresso J-Max', 'Timemore C2', 'Mahlkönig EK43', 'Lagom P64', 'Eureka Mignon'],
  ESPRESSO_MACHINES: ['La Marzocco Linea Mini', 'Breville Dual Boiler', 'Rocket Apartamento', 'Lelit Bianca', 'Gaggia Classic Pro', 'Flair 58', 'Decent DE1', 'Rancilio Silvia', 'Sage Barista Express'],
  POUR_OVER_BRANDS: ['Hario', 'Kalita', 'Chemex', 'Fellow', 'Origami', 'Orea', 'Cafec', 'Hario Switch', 'Clever'],
  POUR_OVER_MODELS: {
    'Hario': ['V60-01', 'V60-02', 'V60-03', 'Mugen'],
    'Kalita': ['Wave 155', 'Wave 185', '102 Dripper'],
    'Fellow': ['Stagg [X]', 'Stagg [XF]'],
    'Orea': ['V3', 'V3 MK2'],
    'Origami': ['Dripper S', 'Dripper M'],
    'Cafec': ['Flower Dripper', 'Deep 27'],
    'Chemex': ['Classic 3-Cup', 'Classic 6-Cup', 'Glass Handle 8-Cup'],
    'Hario Switch': ['Size 02', 'Size 03'],
    'Clever': ['Small', 'Large']
  },
  FILTER_PAPERS: [
    'Hario V60 Tabbed (Japan)', 'Hario V60 Untabbed', 'Cafec Abaca', 'Cafec T-90 (Medium)', 
    'Cafec T-92 (Light)', 'Sibarist Fast', 'Kalita White Wave', 'Kalita Brown Wave', 
    'Chemex Bonded', 'Fellow Stagg [X] Paper', 'Origami Cup Filter', 'Melitta #2', 'Melitta #4', 'Abaca+ Shallow'
  ],
  COLD_BREW_SYSTEMS: ['Toddy System', 'Hario Mizudashi', 'OXO Good Grips', 'Bruer Cold Drip', 'KitchenAid Cold Brew', 'Filtron'],
  FRENCH_PRESS_BRANDS: ['Bodum', 'Espro', 'Fellow Clara', 'Hario', 'Yama'],
  DISTRIBUTION_TOOLS: ['None', 'WDT (Needle Tool)', 'OCD Spinning Tool', 'Palm Distributor', 'WDT + OCD'],
  BASKETS: ['Stock', 'VST 18g', 'VST 20g', 'IMS Precision', 'Pullman 876']
};

interface BrewFormProps {
  coffee: CoffeeBean;
  onSave: (log: Partial<BrewLog>) => void;
  onCancel: () => void;
}

const BrewForm: React.FC<BrewFormProps> = ({ coffee, onSave, onCancel }) => {
  const [method, setMethod] = useState<BrewMethod>(BrewMethod.ESPRESSO);
  const [baristaName, setBaristaName] = useState('');

  // Shared
  const [dose, setDose] = useState(18);
  const [yieldVal, setYieldVal] = useState(36);
  const [time, setTime] = useState(30);
  const [grinder, setGrinder] = useState(EQUIPMENT_DB.GRINDERS[0]);
  const [setting, setSetting] = useState('');
  const [temp, setTemp] = useState(93);
  const [rating, setRating] = useState(4);
  const [notes, setNotes] = useState('');
  const [processNotes, setProcessNotes] = useState('');

  // Espresso specific
  const [machineBrand, setMachineBrand] = useState(EQUIPMENT_DB.ESPRESSO_MACHINES[0]);
  const [basketType, setBasketType] = useState(EQUIPMENT_DB.BASKETS[0]);
  const [distTool, setDistTool] = useState(EQUIPMENT_DB.DISTRIBUTION_TOOLS[0]);
  const [puckScreen, setPuckScreen] = useState(false);
  const [pressure, setPressure] = useState(9);

  // Cold Brew specific
  const [cbSystem, setCbSystem] = useState(EQUIPMENT_DB.COLD_BREW_SYSTEMS[0]);
  const [steepTime, setSteepTime] = useState(16);
  const [bloomTime, setBloomTime] = useState(0); // For cold brew / pour over
  const [coldBrewType, setColdBrewType] = useState<'Concentrate' | 'Ready to Drink'>('Ready to Drink');

  // Pour Over specific
  const [brewerBrand, setBrewerBrand] = useState(EQUIPMENT_DB.POUR_OVER_BRANDS[0]);
  const [brewerModel, setBrewerModel] = useState('');
  const [filterType, setFilterType] = useState(EQUIPMENT_DB.FILTER_PAPERS[0]);
  const [pulsesCount, setPulsesCount] = useState(3);
  const [pourVolumes, setPourVolumes] = useState('');

  // French Press
  const [fpBrand, setFpBrand] = useState(EQUIPMENT_DB.FRENCH_PRESS_BRANDS[0]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSave({
      coffeeId: coffee.id,
      baristaName,
      date: new Date().toISOString(),
      method,
      grinder,
      grindSetting: setting,
      dose,
      yield: yieldVal,
      brewTime: time,
      waterTemp: temp,
      rating,
      tastingNotes: notes.split(',').map(n => n.trim()).filter(n => n !== ''),
      processNotes, // Used as a general method notes text block

      // Espresso
      machine: method === BrewMethod.ESPRESSO ? machineBrand : undefined,
      basketType: method === BrewMethod.ESPRESSO ? basketType : undefined,
      distributionTool: method === BrewMethod.ESPRESSO ? distTool : undefined,
      puckScreen: method === BrewMethod.ESPRESSO ? puckScreen : undefined,
      pressure: method === BrewMethod.ESPRESSO ? pressure : undefined,

      // Cold Brew
      coldBrewSystem: method === BrewMethod.COLD_BREW ? cbSystem : undefined,
      coldBrewType: method === BrewMethod.COLD_BREW ? coldBrewType : undefined,
      steepTime: (method === BrewMethod.COLD_BREW || method === BrewMethod.FRENCH_PRESS) ? steepTime : undefined,
      bloomTime: (method === BrewMethod.COLD_BREW || method === BrewMethod.POUR_OVER) ? bloomTime : undefined,

      // Pour Over
      brewerBrand: method === BrewMethod.POUR_OVER ? brewerBrand : undefined,
      brewer: method === BrewMethod.POUR_OVER ? brewerModel : (method === BrewMethod.FRENCH_PRESS ? fpBrand : undefined),
      filterType: method === BrewMethod.POUR_OVER ? filterType : undefined,
      pourStructure: method === BrewMethod.POUR_OVER ? `${pulsesCount} pours` : undefined,
      pourVolumes: method === BrewMethod.POUR_OVER ? pourVolumes : undefined,
    });
  };

  const ratio = dose > 0 ? `1:${(yieldVal / dose).toFixed(1)}` : '0';

  return (
    <form onSubmit={handleSubmit} className="space-y-6 bg-white p-8 rounded-[3rem] shadow-2xl border border-stone-100 max-w-xl mx-auto max-h-[92vh] overflow-y-auto animate-in zoom-in-95 duration-300 custom-scrollbar">
      <div className="flex justify-between items-start mb-4">
        <div>
          <h2 className="text-3xl font-black display-font text-stone-800">Log Brew</h2>
          <p className="text-xs font-bold text-amber-800 uppercase tracking-widest mt-1">{coffee.name}</p>
        </div>
        <button type="button" onClick={onCancel} className="p-3 bg-stone-50 rounded-full text-stone-400 hover:text-stone-800 transition-colors">✕</button>
      </div>

      {/* METHOD SELECTOR */}
      <div className="flex bg-stone-100 p-1.5 rounded-2xl gap-1 overflow-x-auto no-scrollbar">
        {Object.values(BrewMethod).map(m => (
          <button 
            key={m} 
            type="button"
            onClick={() => setMethod(m)}
            className={`flex-none py-2 px-3 text-[9px] font-black uppercase tracking-tighter rounded-xl transition-all ${method === m ? 'bg-white text-amber-800 shadow-sm' : 'text-stone-400 hover:text-stone-600'}`}
          >
            {m === BrewMethod.POUR_OVER ? 'Filter' : m}
          </button>
        ))}
      </div>

      <div className="space-y-5">
        {/* SHARED EQUIPMENT */}
        <div className="grid grid-cols-2 gap-4">
          <div>
            <label className="block text-[10px] font-bold text-stone-400 uppercase tracking-widest mb-1.5">Grinder</label>
            <select value={grinder} onChange={e => setGrinder(e.target.value)} className="w-full bg-stone-50 border border-stone-200 rounded-xl p-3 text-sm font-bold appearance-none">
              {EQUIPMENT_DB.GRINDERS.map(g => <option key={g} value={g}>{g}</option>)}
              <option value="Other">Other Grinder</option>
            </select>
          </div>
          <div>
            <label className="block text-[10px] font-bold text-stone-400 uppercase tracking-widest mb-1.5">Grind Setting</label>
            <input type="text" value={setting} onChange={e => setSetting(e.target.value)} className="w-full bg-stone-50 border border-stone-200 rounded-xl p-3 text-sm font-bold" placeholder="e.g. 18 clicks" />
          </div>
        </div>

        {/* METHOD SPECIFIC TOOLKIT */}
        <div className="p-6 bg-amber-50/40 rounded-[2rem] border border-amber-100/50 space-y-4 animate-in fade-in duration-500">
          <h4 className="text-[10px] font-black text-amber-800 uppercase tracking-widest flex items-center gap-2">
            <span className="w-1.5 h-1.5 bg-amber-800 rounded-full"></span> {method} Configuration
          </h4>

          {method === BrewMethod.ESPRESSO && (
            <div className="space-y-4">
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-[9px] font-bold text-stone-500 uppercase mb-1">Machine</label>
                  <select value={machineBrand} onChange={e => setMachineBrand(e.target.value)} className="w-full bg-white border border-amber-200 rounded-xl p-3 text-xs font-bold">
                    {EQUIPMENT_DB.ESPRESSO_MACHINES.map(m => <option key={m} value={m}>{m}</option>)}
                  </select>
                </div>
                <div>
                  <label className="block text-[9px] font-bold text-stone-500 uppercase mb-1">Basket</label>
                  <select value={basketType} onChange={e => setBasketType(e.target.value)} className="w-full bg-white border border-amber-200 rounded-xl p-3 text-xs font-bold">
                    {EQUIPMENT_DB.BASKETS.map(b => <option key={b} value={b}>{b}</option>)}
                  </select>
                </div>
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-[9px] font-bold text-stone-500 uppercase mb-1">Distribution</label>
                  <select value={distTool} onChange={e => setDistTool(e.target.value)} className="w-full bg-white border border-amber-200 rounded-xl p-3 text-xs font-bold">
                    {EQUIPMENT_DB.DISTRIBUTION_TOOLS.map(t => <option key={t} value={t}>{t}</option>)}
                  </select>
                </div>
                <div className="flex flex-col justify-end pb-3">
                  <label className="flex items-center gap-2 cursor-pointer group">
                    <input type="checkbox" checked={puckScreen} onChange={e => setPuckScreen(e.target.checked)} className="w-4 h-4 text-amber-800 border-stone-300 rounded focus:ring-amber-500" />
                    <span className="text-[10px] font-black uppercase tracking-widest text-stone-500 group-hover:text-amber-800 transition-colors">Puck Screen?</span>
                  </label>
                </div>
              </div>
            </div>
          )}

          {method === BrewMethod.POUR_OVER && (
            <div className="space-y-4">
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-[9px] font-bold text-stone-500 uppercase mb-1">Brewer</label>
                  <select value={brewerBrand} onChange={e => setBrewerBrand(e.target.value)} className="w-full bg-white border border-amber-200 rounded-xl p-3 text-xs font-bold">
                    {EQUIPMENT_DB.POUR_OVER_BRANDS.map(b => <option key={b} value={b}>{b}</option>)}
                  </select>
                </div>
                <div>
                  <label className="block text-[9px] font-bold text-stone-500 uppercase mb-1">Model</label>
                  <select value={brewerModel} onChange={e => setBrewerModel(e.target.value)} className="w-full bg-white border border-amber-200 rounded-xl p-3 text-xs font-bold">
                    <option value="">Select Model</option>
                    {(EQUIPMENT_DB.POUR_OVER_MODELS[brewerBrand as keyof typeof EQUIPMENT_DB.POUR_OVER_MODELS] || []).map(m => (
                      <option key={m} value={m}>{m}</option>
                    ))}
                  </select>
                </div>
              </div>
              <div>
                <label className="block text-[9px] font-bold text-stone-500 uppercase mb-1">Filter Paper</label>
                <select value={filterType} onChange={e => setFilterType(e.target.value)} className="w-full bg-white border border-amber-200 rounded-xl p-3 text-xs font-bold">
                  {EQUIPMENT_DB.FILTER_PAPERS.map(p => <option key={p} value={p}>{p}</option>)}
                </select>
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-[9px] font-bold text-stone-500 uppercase mb-1">Bloom (s)</label>
                  <input type="number" value={bloomTime} onChange={e => setBloomTime(Number(e.target.value))} className="w-full bg-white border border-amber-200 rounded-xl p-3 text-xs font-bold" />
                </div>
                <div>
                  <label className="block text-[9px] font-bold text-stone-500 uppercase mb-1">Pours (Count)</label>
                  <input type="number" value={pulsesCount} onChange={e => setPulsesCount(Number(e.target.value))} className="w-full bg-white border border-amber-200 rounded-xl p-3 text-xs font-bold" />
                </div>
              </div>
              <div>
                <label className="block text-[9px] font-bold text-stone-500 uppercase mb-1">Pours Volume (g sequence)</label>
                <input type="text" value={pourVolumes} onChange={e => setPourVolumes(e.target.value)} className="w-full bg-white border border-amber-200 rounded-xl p-3 text-xs font-bold" placeholder="e.g. 50, 70, 70, 60" />
              </div>
            </div>
          )}

          {method === BrewMethod.COLD_BREW && (
            <div className="space-y-4">
              <div>
                <label className="block text-[9px] font-bold text-stone-500 uppercase mb-1">System</label>
                <select value={cbSystem} onChange={e => setCbSystem(e.target.value)} className="w-full bg-white border border-amber-200 rounded-xl p-3 text-xs font-bold">
                  {EQUIPMENT_DB.COLD_BREW_SYSTEMS.map(s => <option key={s} value={s}>{s}</option>)}
                </select>
              </div>
              <div className="flex gap-4">
                <label className="flex items-center gap-2 cursor-pointer">
                  <input type="radio" checked={coldBrewType === 'Ready to Drink'} onChange={() => setColdBrewType('Ready to Drink')} className="w-4 h-4 text-amber-800" />
                  <span className="text-[10px] font-black uppercase text-stone-500">RTD</span>
                </label>
                <label className="flex items-center gap-2 cursor-pointer">
                  <input type="radio" checked={coldBrewType === 'Concentrate'} onChange={() => setColdBrewType('Concentrate')} className="w-4 h-4 text-amber-800" />
                  <span className="text-[10px] font-black uppercase text-stone-500">Concentrate</span>
                </label>
              </div>
            </div>
          )}

          {method === BrewMethod.FRENCH_PRESS && (
            <div>
              <label className="block text-[9px] font-bold text-stone-500 uppercase mb-1">Press Vessel</label>
              <select value={fpBrand} onChange={e => setFpBrand(e.target.value)} className="w-full bg-white border border-amber-200 rounded-xl p-3 text-xs font-bold">
                {EQUIPMENT_DB.FRENCH_PRESS_BRANDS.map(b => <option key={b} value={b}>{b}</option>)}
              </select>
            </div>
          )}
        </div>

        {/* METRICS */}
        <div className="grid grid-cols-3 gap-3 p-6 bg-stone-50 rounded-[2rem] border border-stone-100">
          <div>
            <label className="block text-[9px] font-black text-stone-400 uppercase tracking-widest mb-1.5 text-center">Dose (g)</label>
            <input type="number" step="0.1" value={dose} onChange={e => setDose(Number(e.target.value))} className="w-full bg-white border border-stone-200 rounded-xl p-3 text-center text-sm font-black" />
          </div>
          <div>
            <label className="block text-[9px] font-black text-stone-400 uppercase tracking-widest mb-1.5 text-center">Yield (g)</label>
            <input type="number" step="1" value={yieldVal} onChange={e => setYieldVal(Number(e.target.value))} className="w-full bg-white border border-stone-200 rounded-xl p-3 text-center text-sm font-black" />
          </div>
          <div>
            <label className="block text-[9px] font-black text-stone-400 uppercase tracking-widest mb-1.5 text-center">Ratio</label>
            <div className="w-full bg-amber-100/50 border border-amber-200 rounded-xl p-3 text-center text-sm font-black text-amber-900">{ratio}</div>
          </div>
        </div>

        {/* TIME & TEMP */}
        <div className="grid grid-cols-2 gap-4">
          <div>
            <label className="block text-[10px] font-bold text-stone-400 uppercase tracking-widest mb-1.5">Water Temp (°C)</label>
            <input type="number" value={temp} onChange={e => setTemp(Number(e.target.value))} className="w-full bg-stone-50 border border-stone-200 rounded-xl p-3 text-sm font-bold" />
          </div>
          <div>
            <label className="block text-[10px] font-bold text-stone-400 uppercase tracking-widest mb-1.5">
              {method === BrewMethod.COLD_BREW ? 'Steep (Hrs)' : 'Brew Time (s)'}
            </label>
            <input 
              type="number" 
              value={method === BrewMethod.COLD_BREW ? steepTime : time} 
              onChange={e => method === BrewMethod.COLD_BREW ? setSteepTime(Number(e.target.value)) : setTime(Number(e.target.value))} 
              className="w-full bg-stone-50 border border-stone-200 rounded-xl p-3 text-sm font-bold" 
            />
          </div>
        </div>

        {/* PROCESS NOTES / TEXT BLOCK */}
        <div>
          <label className="block text-[10px] font-bold text-stone-400 uppercase tracking-widest mb-1.5">Method Notes / Process Steps</label>
          <textarea value={processNotes} onChange={e => setProcessNotes(e.target.value)} className="w-full bg-stone-50 border border-stone-200 rounded-xl p-4 text-sm h-32 font-medium" placeholder="Describe your technique, bloom details, or any specific steps used during the brew..."></textarea>
        </div>

        {/* TASTING NOTES */}
        <div>
          <label className="block text-[10px] font-bold text-stone-400 uppercase tracking-widest mb-1.5">Flavor Impressions</label>
          <textarea value={notes} onChange={e => setNotes(e.target.value)} className="w-full bg-stone-50 border border-stone-200 rounded-xl p-4 text-sm h-20 font-medium" placeholder="Comma separated: Cherry, Caramel, Bright..."></textarea>
        </div>

        {/* RATING */}
        <div className="flex items-center justify-between border-t border-stone-100 pt-6">
          <label className="text-[10px] font-black text-stone-400 uppercase tracking-widest">Recipe Rating</label>
          <div className="flex gap-2">
            {[1,2,3,4,5].map(star => (
              <button key={star} type="button" onClick={() => setRating(star)} className={`transition-all ${rating >= star ? 'text-amber-500 scale-110' : 'text-stone-200 hover:text-stone-300'}`}>
                <svg className="w-9 h-9 fill-current" viewBox="0 0 20 20"><path d="M9.049 2.927c.3-.921 1.603-.921 1.902 0l1.07 3.292a1 1 0 00.95.69h3.462c.969 0 1.371 1.24.588 1.81l-2.8 2.034a1 1 0 00-.364 1.118l1.07 3.292c.3.921-.755 1.688-1.54 1.118l-2.8-2.034a1 1 0 00-1.175 0l-2.8 2.034c-.784.57-1.838-.197-1.539-1.118l1.07-3.292a1 1 0 00-.364-1.118L2.98 8.72c-.783-.57-.38-1.81.588-1.81h3.461a1 1 0 00.951-.69l1.07-3.292z" /></svg>
              </button>
            ))}
          </div>
        </div>
      </div>

      <div className="flex gap-4 pt-4 sticky bottom-0 bg-white/95 backdrop-blur-sm py-4 border-t border-stone-100 mt-2 z-10">
        <button type="button" onClick={onCancel} className="flex-1 py-4 bg-stone-100 text-stone-500 rounded-2xl font-black uppercase text-[10px] tracking-[0.2em] hover:bg-stone-200 transition-all">Discard</button>
        <button type="submit" className="flex-1 py-4 bg-stone-900 text-white rounded-2xl font-black uppercase text-[10px] tracking-[0.2em] hover:bg-black transition-all shadow-xl shadow-stone-900/20 active:scale-[0.98]">Log Brew</button>
      </div>
    </form>
  );
};

