                <Icons.Coffee className="w-16 h-16 text-stone-100 mx-auto mb-4" />
                <p className="text-stone-400 font-bold uppercase text-[10px] tracking-widest">Your journal is empty</p>
                <button onClick={startBrewCapture} className="mt-4 text-amber-800 font-bold text-sm underline underline-offset-4">Log your first calibration</button>
              </div>
            ) : (
              <div className="space-y-6">
                {brewLogs.map(log => {
                  const coffee = coffees.find(c => c.id === log.coffeeId);
                  return (
                    <div key={log.id} className="bg-white p-7 rounded-[2.5rem] shadow-sm border border-stone-100 hover:border-amber-200 transition-all group relative overflow-hidden">
                      <div className="flex justify-between mb-5">
                        <div className="flex-1">
                          <div className="flex flex-wrap items-center gap-2 mb-2">
                            <span className="text-[9px] uppercase font-black text-amber-800 bg-amber-50 px-2 py-0.5 rounded-md">{log.method}</span>
                            {log.machine && <span className="text-[9px] uppercase font-bold text-stone-500 bg-stone-50 px-2 py-0.5 rounded-md">{log.machine}</span>}
                            {log.coldBrewSystem && <span className="text-[9px] uppercase font-bold text-stone-500 bg-stone-50 px-2 py-0.5 rounded-md">{log.coldBrewSystem}</span>}
                            {log.brewerBrand && <span className="text-[9px] uppercase font-bold text-stone-500 bg-stone-50 px-2 py-0.5 rounded-md">{log.brewerBrand} {log.brewer}</span>}
                            {log.aeroMethod && <span className="text-[9px] uppercase font-bold text-stone-500 bg-stone-50 px-2 py-0.5 rounded-md">{log.aeroMethod}</span>}
                          </div>
                          <h3 className="font-bold text-2xl text-stone-800 leading-tight">{coffee?.name || 'Unknown Blend'}</h3>
                          <p className="text-[10px] text-stone-400 font-black uppercase tracking-widest mt-1.5 flex flex-wrap items-center gap-2">
                             {log.grinder} • <span className="text-amber-700">{log.grindSetting}</span>
                             {log.distributionTool && log.distributionTool !== 'None' && <span className="opacity-50">| Dist: {log.distributionTool}</span>}
                             {log.filterType && <span className="opacity-50">| Filter: {log.filterType}</span>}
                             {log.filterCapUsed && <span className="opacity-50">| Cap: {log.filterCapUsed}</span>}
                             {log.agitation && log.agitation !== 'None' && <span className="opacity-50">| Agit: {log.agitation}</span>}
                          </p>
                        </div>
                        <div className="text-right">
                          <p className="text-[10px] text-stone-300 font-black uppercase tracking-tighter">{new Date(log.date).toLocaleDateString()}</p>
                          <div className="flex gap-0.5 text-amber-500 mt-2">
                            {[...Array(5)].map((_, i) => (
                              <Icons.Star key={i} className={`w-3.5 h-3.5 ${i < log.rating ? 'fill-current' : 'text-stone-100'}`} />
                            ))}
                          </div>
                        </div>
                      </div>

                      <div className="grid grid-cols-4 gap-4 bg-stone-50/80 p-5 rounded-2xl text-center mb-4">
                        <div className="flex flex-col"><p className="text-[9px] text-stone-400 font-black uppercase mb-1">Dose</p><p className="font-black text-stone-800 text-sm">{log.dose}g</p></div>
                        <div className="flex flex-col"><p className="text-[9px] text-stone-400 font-black uppercase mb-1">Yield</p><p className="font-black text-stone-800 text-sm">{log.yield}g</p></div>
                        <div className="flex flex-col">
                          <p className="text-[9px] text-stone-400 font-black uppercase mb-1">{log.method === BrewMethod.COLD_BREW ? 'Steep' : 'Time'}</p>
                          <p className="font-black text-stone-800 text-sm">
                            {log.method === BrewMethod.COLD_BREW ? `${log.steepTime}h` : `${log.brewTime}s`}
                          </p>
                        </div>
                        <div className="flex flex-col"><p className="text-[9px] text-stone-400 font-black uppercase mb-1">Temp</p><p className="font-black text-stone-800 text-sm">{log.waterTemp}°C</p></div>
                      </div>

                      {log.method === BrewMethod.POUR_OVER && (log.bloomTime || log.pourStructure || log.pourVolumes) && (
                        <div className="mb-4 grid grid-cols-2 gap-4 text-[10px] font-bold text-stone-500 bg-stone-50/50 p-3 rounded-xl">
                          {log.bloomTime && <div><span className="text-stone-300 uppercase block mb-1">Bloom</span>{log.bloomTime}s</div>}
                          {log.pourStructure && <div><span className="text-stone-300 uppercase block mb-1">Pours</span>{log.pourStructure}</div>}
                          {log.pourVolumes && <div className="col-span-2"><span className="text-stone-300 uppercase block mb-1">Volumes</span>{log.pourVolumes}</div>}
                        </div>
                      )}

                      {log.method === BrewMethod.AEROPRESS && (log.steepTime || log.plungeTime || log.aeroPourVolumes) && (
                        <div className="mb-4 grid grid-cols-2 gap-4 text-[10px] font-bold text-stone-500 bg-stone-50/50 p-3 rounded-xl">
                          {log.steepTime && <div><span className="text-stone-300 uppercase block mb-1">Steep</span>{log.steepTime}s</div>}
                          {log.plungeTime && <div><span className="text-stone-300 uppercase block mb-1">Plunge</span>{log.plungeTime}s</div>}
                          {log.aeroPourVolumes && <div className="col-span-2"><span className="text-stone-300 uppercase block mb-1">Volumes</span>{log.aeroPourVolumes}</div>}
                        </div>
                      )}

                      {log.method === BrewMethod.FRENCH_PRESS && (log.timeBeforePlunge || log.agitation) && (
                        <div className="mb-4 grid grid-cols-2 gap-4 text-[10px] font-bold text-stone-500 bg-stone-50/50 p-3 rounded-xl">
                          {log.timeBeforePlunge && <div><span className="text-stone-300 uppercase block mb-1">Plunge Wait</span>{log.timeBeforePlunge}s</div>}
                          {log.agitation && <div><span className="text-stone-300 uppercase block mb-1">Agitation</span>{log.agitation} {log.agitationDuration ? `(${log.agitationDuration}s)` : ''}</div>}
                        </div>
                      )}

                      {log.processNotes && (
                        <div className="mb-4 p-4 bg-amber-50/30 rounded-xl border border-amber-100/50">
                          <p className="text-[9px] font-black text-amber-800 uppercase tracking-widest mb-1">Method Notes</p>
                          <p className="text-xs text-stone-600 leading-relaxed font-medium whitespace-pre-wrap italic">"{log.processNotes}"</p>
                        </div>
                      )}

                      {log.tastingNotes && log.tastingNotes.length > 0 && (
                        <div className="flex flex-wrap gap-2">
                          {log.tastingNotes.map((note, idx) => (
                            <span key={idx} className="text-[9px] font-black text-stone-400 uppercase tracking-widest bg-stone-100 px-2 py-1 rounded-md">
                              {note}
                            </span>
                          ))}
                        </div>
                      )}
                    </div>
                  );
                })}
              </div>
            )}
          </div>
        )}

        {activeTab === 'library' && (
          <div className="animate-in fade-in slide-in-from-bottom-4 duration-500">
            <div className="flex justify-between items-center mb-8">
              <h2 className="text-3xl font-bold text-stone-800 display-font">Coffee Library</h2>
              <button onClick={() => setShowBeanForm(true)} className="bg-stone-900 text-white p-4 px-6 rounded-2xl flex items-center gap-2 text-[10px] font-black uppercase tracking-[0.2em] active:scale-95 transition-all shadow-xl shadow-stone-900/10">
                <Icons.Plus className="w-4 h-4" /> Add Bean
              </button>
            </div>
            <div className="grid grid-cols-1 gap-6">
              {coffees.map(coffee => (
                <CoffeeCard key={coffee.id} coffee={coffee} onClick={(c) => { setSelectedCoffee(c); setBrewFlowStep('brew'); setShowBrewFlow(true); }} />
              ))}
            </div>
          </div>
        )}

        {activeTab === 'grind' && <GrindReference />}

        {activeTab === 'community' && (
           <div className="animate-in fade-in slide-in-from-bottom-4 duration-500 py-12 text-center">
              <div className="w-20 h-20 bg-amber-100 rounded-[2rem] flex items-center justify-center mx-auto mb-6 text-amber-800">
                <Icons.Users className="w-8 h-8" />
              </div>
              <h3 className="text-2xl font-bold display-font mb-2">Community Feed</h3>
              <p className="text-stone-400 text-sm font-medium mb-8">Coming soon: Share your calibration recipes with baristas worldwide.</p>
              <button className="bg-stone-900 text-white px-8 py-4 rounded-2xl font-black uppercase text-[10px] tracking-widest opacity-50 cursor-not-allowed">Join Waitlist</button>
           </div>
        )}
      </main>

      {/* MODALS */}
      {showBrewFlow && (
        <div className="fixed inset-0 bg-stone-900/60 backdrop-blur-md flex items-center justify-center z-[70] p-6 overflow-y-auto">
          {brewFlowStep === 'select' && (
            <div className="bg-white rounded-[3rem] w-full max-w-md p-10 shadow-2xl animate-in zoom-in-95 duration-300">
              <div className="flex justify-between items-center mb-8">
                <div>
                   <h3 className="text-2xl font-black text-stone-800 display-font">Select Roast</h3>
                   <p className="text-xs text-stone-400 font-medium">Which bean are we calibrating today?</p>
                </div>
                <button onClick={() => setShowBrewFlow(false)} className="p-2 bg-stone-50 rounded-full text-stone-400 hover:text-stone-800 transition-colors">✕</button>
              </div>
              <div className="space-y-4 max-h-96 overflow-y-auto mb-8 pr-2 custom-scrollbar">
                {coffees.map(c => (
                  <button key={c.id} onClick={() => { setSelectedCoffee(c); setBrewFlowStep('brew'); }} className="w-full text-left p-5 rounded-[1.5rem] border border-stone-100 hover:border-amber-400 hover:bg-amber-50/50 transition-all flex justify-between items-center group">
                    <div>
                      <p className="font-black text-stone-800 group-hover:text-amber-900">{c.name}</p>
                      <p className="text-[10px] text-stone-400 font-black uppercase tracking-widest">{c.roaster}</p>
                    </div>
                    <div className="text-right">
                      <span className="text-[10px] font-black text-amber-800 bg-amber-100 px-2 py-1 rounded-md">{c.remainingWeight}g</span>
                    </div>
                  </button>
                ))}
              </div>
              <button 
                onClick={() => setBrewFlowStep('new-bean')}
                className="w-full py-5 border-2 border-dashed border-stone-200 text-stone-400 rounded-3xl font-black uppercase text-[10px] tracking-[0.2em] hover:border-amber-400 hover:text-amber-800 hover:bg-amber-50/30 transition-all"
              >
                + Register New Bean
              </button>
            </div>
          )}

          {brewFlowStep === 'new-bean' && (
            <CoffeeBeanForm 
              onSave={handleAddBean} 
              onCancel={() => setBrewFlowStep('select')} 
            />
          )}

          {brewFlowStep === 'brew' && selectedCoffee && (
            <BrewForm 
              coffee={selectedCoffee} 
              onSave={handleSaveBrew} 
              onCancel={() => setBrewFlowStep('select')} 
            />
          )}
        </div>
      )}

      {showBeanForm && (
        <div className="fixed inset-0 bg-stone-900/60 backdrop-blur-md flex items-center justify-center z-[70] p-6 overflow-y-auto">
          <CoffeeBeanForm onSave={handleAddBean} onCancel={() => setShowBeanForm(false)} />
        </div>
      )}

      <nav className="fixed bottom-6 left-1/2 -translate-x-1/2 w-[calc(100%-3rem)] max-w-md bg-stone-900/90 backdrop-blur-xl border border-white/10 px-5 py-5 flex justify-around items-center z-50 rounded-[3rem] shadow-2xl">
        {[
          { id: 'journal', icon: <Icons.Book className="w-6 h-6" />, label: 'Journal' },
          { id: 'library', icon: <Icons.Coffee className="w-6 h-6" />, label: 'Library' },
          { id: 'grind', icon: <Icons.Search className="w-6 h-6" />, label: 'Reference' },
          { id: 'community', icon: <Icons.Users className="w-6 h-6" />, label: 'Community' }
        ].map(item => (
          <button key={item.id} onClick={() => setActiveTab(item.id as any)} className={`flex flex-col items-center gap-1.5 transition-all group ${activeTab === item.id ? 'text-amber-400' : 'text-stone-500 hover:text-stone-300'}`}>
            <div className={`p-2.5 rounded-2xl transition-all ${activeTab === item.id ? 'bg-amber-400/10 scale-110 shadow-inner' : 'group-hover:bg-white/5'}`}>{item.icon}</div>
            <span className={`text-[8px] font-black uppercase tracking-[0.3em] ${activeTab === item.id ? 'opacity-100' : 'opacity-40'}`}>{item.label}</span>
          </button>
        ))}
      </nav>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { BrewMethod, CoffeeBean, BrewLog } from '../types';

const EQUIPMENT_DB = {
  GRINDERS: ['Niche Zero', 'Fellow Ode Gen 2', 'Comandante C40', 'Baratza Encore', '1Zpresso J-Max', 'Timemore C2', 'Mahlkönig EK43', 'Lagom P64', 'Eureka Mignon'],
  ESPRESSO_MACHINES: ['La Marzocco Linea Mini', 'Breville Dual Boiler', 'Rocket Apartamento', 'Lelit Bianca', 'Gaggia Classic Pro', 'Flair 58', 'Decent DE1', 'Rancilio Silvia', 'Sage Barista Express'],
  POUR_OVER_BRANDS: ['Hario', 'Kalita', 'Chemex', 'Fellow', 'Origami', 'Orea', 'Cafec', 'Hario Switch', 'Clever'],
  POUR_OVER_MODELS: {
    'Hario': ['V60-01', 'V60-02', 'V60-03', 'Mugen'],
    'Kalita': ['Wave 155', 'Wave 185', '102 Dripper'],
    'Fellow': ['Stagg [X]', 'Stagg [XF]'],
    'Orea': ['V3', 'V3 MK2'],
    'Origami': ['Dripper S', 'Dripper M'],
    'Cafec': ['Flower Dripper', 'Deep 27'],
    'Chemex': ['Classic 3-Cup', 'Classic 6-Cup', 'Glass Handle 8-Cup'],
    'Hario Switch': ['Size 02', 'Size 03'],
    'Clever': ['Small', 'Large']
  },
  FILTER_PAPERS: [
    'Hario V60 Tabbed (Japan)', 'Hario V60 Untabbed', 'Cafec Abaca', 'Cafec T-90 (Medium)', 
    'Cafec T-92 (Light)', 'Sibarist Fast', 'Kalita White Wave', 'Kalita Brown Wave', 
    'Chemex Bonded', 'Fellow Stagg [X] Paper', 'Origami Cup Filter', 'Melitta #2', 'Melitta #4', 'Abaca+ Shallow'
  ],
  AEROPRESS_STYLES: [
    'Standard (Upright)', 'Inverted', 'Bypass (Dilution)', 'Espresso-style', 
    'Cold Drip setup', 'Hoffmann Style', 'Adler Method', 'WAC Winner Style'
  ],
  AEROPRESS_CAPS: [
    'Standard Plastic Cap', 'Fellow Prismo', 'AeroPress Flow Control Cap', 
    'Joepresso', 'PuckPuck Attachment', 'Metal Mesh Filter', '2uul / 3rd Party'
  ],
  COLD_BREW_SYSTEMS: ['Toddy System', 'Hario Mizudashi', 'OXO Good Grips', 'Bruer Cold Drip', 'KitchenAid Cold Brew', 'Filtron'],
  FRENCH_PRESS_BRANDS: ['Bodum', 'Espro', 'Fellow Clara', 'Hario', 'Yama'],
  AGITATION_METHODS: ['None', 'Gentle Stir', 'Aggressive Stir', 'Swirl', 'Break Crust', 'Double Stir'],
  DISTRIBUTION_TOOLS: ['None', 'WDT (Needle Tool)', 'OCD Spinning Tool', 'Palm Distributor', 'WDT + OCD'],
  BASKETS: ['Stock', 'VST 18g', 'VST 20g', 'IMS Precision', 'Pullman 876']
};

interface BrewFormProps {
  coffee: CoffeeBean;
  onSave: (log: Partial<BrewLog>) => void;
  onCancel: () => void;
}

const BrewForm: React.FC<BrewFormProps> = ({ coffee, onSave, onCancel }) => {
  const [method, setMethod] = useState<BrewMethod>(BrewMethod.ESPRESSO);
  const [baristaName, setBaristaName] = useState('');

  // Shared
  const [dose, setDose] = useState(18);
  const [yieldVal, setYieldVal] = useState(36);
  const [time, setTime] = useState(30);
  const [grinder, setGrinder] = useState(EQUIPMENT_DB.GRINDERS[0]);
  const [setting, setSetting] = useState('');
  const [temp, setTemp] = useState(93);
  const [rating, setRating] = useState(4);
  const [notes, setNotes] = useState('');
  const [processNotes, setProcessNotes] = useState('');

  // Espresso specific
  const [machineBrand, setMachineBrand] = useState(EQUIPMENT_DB.ESPRESSO_MACHINES[0]);
  const [basketType, setBasketType] = useState(EQUIPMENT_DB.BASKETS[0]);
  const [distTool, setDistTool] = useState(EQUIPMENT_DB.DISTRIBUTION_TOOLS[0]);
  const [puckScreen, setPuckScreen] = useState(false);
  const [pressure, setPressure] = useState(9);

  // Cold Brew specific
  const [cbSystem, setCbSystem] = useState(EQUIPMENT_DB.COLD_BREW_SYSTEMS[0]);
  const [steepTimeCB, setSteepTimeCB] = useState(16);
  const [bloomTime, setBloomTime] = useState(0); 
  const [coldBrewType, setColdBrewType] = useState<'Concentrate' | 'Ready to Drink'>('Ready to Drink');

  // Pour Over specific
  const [brewerBrand, setBrewerBrand] = useState(EQUIPMENT_DB.POUR_OVER_BRANDS[0]);
  const [brewerModel, setBrewerModel] = useState('');
  const [filterType, setFilterType] = useState(EQUIPMENT_DB.FILTER_PAPERS[0]);
  const [pulsesCount, setPulsesCount] = useState(3);
  const [pourVolumes, setPourVolumes] = useState('');

  // AeroPress specific
  const [aeroMethod, setAeroMethod] = useState(EQUIPMENT_DB.AEROPRESS_STYLES[0]);
  const [filterCap, setFilterCap] = useState(EQUIPMENT_DB.AEROPRESS_CAPS[0]);
  const [steepTimeAP, setSteepTimeAP] = useState(120);
  const [plungeTime, setPlungeTime] = useState(30);
  const [aeroPourVolumes, setAeroPourVolumes] = useState('');

  // French Press specific
  const [fpBrand, setFpBrand] = useState(EQUIPMENT_DB.FRENCH_PRESS_BRANDS[0]);
  const [fpImmersionTime, setFpImmersionTime] = useState(240); // 4 mins
  const [fpPlungeWait, setFpPlungeWait] = useState(30);
  const [fpAgitation, setFpAgitation] = useState(EQUIPMENT_DB.AGITATION_METHODS[0]);
  const [fpAgitationDuration, setFpAgitationDuration] = useState(0);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSave({
      coffeeId: coffee.id,
      baristaName,
      date: new Date().toISOString(),
      method,
      grinder,
      grindSetting: setting,
      dose,
      yield: yieldVal,
      brewTime: method === BrewMethod.COLD_BREW ? steepTimeCB : (method === BrewMethod.FRENCH_PRESS ? fpImmersionTime : time),
      waterTemp: temp,
      rating,
      tastingNotes: notes.split(',').map(n => n.trim()).filter(n => n !== ''),
      processNotes,

      // Espresso
      machine: method === BrewMethod.ESPRESSO ? machineBrand : undefined,
      basketType: method === BrewMethod.ESPRESSO ? basketType : undefined,
      distributionTool: method === BrewMethod.ESPRESSO ? distTool : undefined,
      puckScreen: method === BrewMethod.ESPRESSO ? puckScreen : undefined,
      pressure: method === BrewMethod.ESPRESSO ? pressure : undefined,

      // Cold Brew
      coldBrewSystem: method === BrewMethod.COLD_BREW ? cbSystem : undefined,
      coldBrewType: method === BrewMethod.COLD_BREW ? coldBrewType : undefined,
      steepTime: method === BrewMethod.COLD_BREW ? steepTimeCB : (method === BrewMethod.AEROPRESS ? steepTimeAP : (method === BrewMethod.FRENCH_PRESS ? fpImmersionTime : undefined)),
      bloomTime: (method === BrewMethod.COLD_BREW || method === BrewMethod.POUR_OVER) ? bloomTime : undefined,

      // Pour Over / French Press shared brand property
      // Fix: Consolidated duplicate brewerBrand property to avoid object literal error
      brewerBrand: method === BrewMethod.POUR_OVER ? brewerBrand : (method === BrewMethod.FRENCH_PRESS ? fpBrand : undefined),
      brewer: method === BrewMethod.POUR_OVER ? brewerModel : undefined,
      filterType: method === BrewMethod.POUR_OVER ? filterType : undefined,
      pourStructure: method === BrewMethod.POUR_OVER ? `${pulsesCount} pours` : undefined,
      pourVolumes: method === BrewMethod.POUR_OVER ? pourVolumes : undefined,

      // AeroPress
      aeroMethod: method === BrewMethod.AEROPRESS ? aeroMethod : undefined,
      filterCapUsed: method === BrewMethod.AEROPRESS ? filterCap : undefined,
      plungeTime: method === BrewMethod.AEROPRESS ? plungeTime : undefined,
      aeroPourVolumes: method === BrewMethod.AEROPRESS ? aeroPourVolumes : undefined,

      // French Press specifics
      timeBeforePlunge: method === BrewMethod.FRENCH_PRESS ? fpPlungeWait : undefined,
      agitation: method === BrewMethod.FRENCH_PRESS ? fpAgitation : undefined,
      agitationDuration: method === BrewMethod.FRENCH_PRESS ? fpAgitationDuration : undefined,
    });
  };

  const ratio = dose > 0 ? `1:${(yieldVal / dose).toFixed(1)}` : '0';

  return (
    <form onSubmit={handleSubmit} className="space-y-6 bg-white p-8 rounded-[3rem] shadow-2xl border border-stone-100 max-w-xl mx-auto max-h-[92vh] overflow-y-auto animate-in zoom-in-95 duration-300 custom-scrollbar">
      <div className="flex justify-between items-start mb-4">
        <div>
          <h2 className="text-3xl font-black display-font text-stone-800">Log Brew</h2>
          <p className="text-xs font-bold text-amber-800 uppercase tracking-widest mt-1">{coffee.name}</p>
        </div>
        <button type="button" onClick={onCancel} className="p-3 bg-stone-50 rounded-full text-stone-400 hover:text-stone-800 transition-colors">✕</button>
      </div>

      <div className="flex bg-stone-100 p-1.5 rounded-2xl gap-1 overflow-x-auto no-scrollbar">
        {Object.values(BrewMethod).map(m => (
          <button 
            key={m} 
            type="button"
            onClick={() => setMethod(m)}
            className={`flex-none py-2 px-3 text-[9px] font-black uppercase tracking-tighter rounded-xl transition-all ${method === m ? 'bg-white text-amber-800 shadow-sm' : 'text-stone-400 hover:text-stone-600'}`}
          >
            {m === BrewMethod.POUR_OVER ? 'Filter' : m}
          </button>
        ))}
      </div>

      <div className="space-y-5">
        <div className="grid grid-cols-2 gap-4">
          <div>
            <label className="block text-[10px] font-bold text-stone-400 uppercase tracking-widest mb-1.5">Grinder</label>
            <select value={grinder} onChange={e => setGrinder(e.target.value)} className="w-full bg-stone-50 border border-stone-200 rounded-xl p-3 text-sm font-bold appearance-none">
              {EQUIPMENT_DB.GRINDERS.map(g => <option key={g} value={g}>{g}</option>)}
              <option value="Other">Other Grinder</option>
            </select>
          </div>
          <div>
            <label className="block text-[10px] font-bold text-stone-400 uppercase tracking-widest mb-1.5">Grind Setting</label>
            <input type="text" value={setting} onChange={e => setSetting(e.target.value)} className="w-full bg-stone-50 border border-stone-200 rounded-xl p-3 text-sm font-bold" placeholder="e.g. 18 clicks" />
          </div>
        </div>

        <div className="p-6 bg-amber-50/40 rounded-[2rem] border border-amber-100/50 space-y-4 animate-in fade-in duration-500">
          <h4 className="text-[10px] font-black text-amber-800 uppercase tracking-widest flex items-center gap-2">
            <span className="w-1.5 h-1.5 bg-amber-800 rounded-full"></span> {method} Configuration
          </h4>

          {method === BrewMethod.ESPRESSO && (
            <div className="space-y-4">
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-[9px] font-bold text-stone-500 uppercase mb-1">Machine</label>
                  <select value={machineBrand} onChange={e => setMachineBrand(e.target.value)} className="w-full bg-white border border-amber-200 rounded-xl p-3 text-xs font-bold">
                    {EQUIPMENT_DB.ESPRESSO_MACHINES.map(m => <option key={m} value={m}>{m}</option>)}
                  </select>
                </div>
                <div>
                  <label className="block text-[9px] font-bold text-stone-500 uppercase mb-1">Basket</label>
                  <select value={basketType} onChange={e => setBasketType(e.target.value)} className="w-full bg-white border border-amber-200 rounded-xl p-3 text-xs font-bold">
                    {EQUIPMENT_DB.BASKETS.map(b => <option key={b} value={b}>{b}</option>)}
                  </select>
                </div>
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-[9px] font-bold text-stone-500 uppercase mb-1">Distribution</label>
                  <select value={distTool} onChange={e => setDistTool(e.target.value)} className="w-full bg-white border border-amber-200 rounded-xl p-3 text-xs font-bold">
                    {EQUIPMENT_DB.DISTRIBUTION_TOOLS.map(t => <option key={t} value={t}>{t}</option>)}
                  </select>
                </div>
                <div className="flex flex-col justify-end pb-3">
                  <label className="flex items-center gap-2 cursor-pointer group">
                    <input type="checkbox" checked={puckScreen} onChange={e => setPuckScreen(e.target.checked)} className="w-4 h-4 text-amber-800 border-stone-300 rounded focus:ring-amber-500" />
                    <span className="text-[10px] font-black uppercase tracking-widest text-stone-500 group-hover:text-amber-800 transition-colors">Puck Screen?</span>
                  </label>
                </div>
              </div>
            </div>
          )}

          {method === BrewMethod.POUR_OVER && (
            <div className="space-y-4">
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-[9px] font-bold text-stone-500 uppercase mb-1">Brewer</label>
                  <select value={brewerBrand} onChange={e => setBrewerBrand(e.target.value)} className="w-full bg-white border border-amber-200 rounded-xl p-3 text-xs font-bold">
                    {EQUIPMENT_DB.POUR_OVER_BRANDS.map(b => <option key={b} value={b}>{b}</option>)}
                  </select>
                </div>
                <div>
                  <label className="block text-[9px] font-bold text-stone-500 uppercase mb-1">Model</label>
                  <select value={brewerModel} onChange={e => setBrewerModel(e.target.value)} className="w-full bg-white border border-amber-200 rounded-xl p-3 text-xs font-bold">
                    <option value="">Select Model</option>
                    {(EQUIPMENT_DB.POUR_OVER_MODELS[brewerBrand as keyof typeof EQUIPMENT_DB.POUR_OVER_MODELS] || []).map(m => (
                      <option key={m} value={m}>{m}</option>
                    ))}
                  </select>
                </div>
              </div>
              <div>
                <label className="block text-[9px] font-bold text-stone-500 uppercase mb-1">Filter Paper</label>
                <select value={filterType} onChange={e => setFilterType(e.target.value)} className="w-full bg-white border border-amber-200 rounded-xl p-3 text-xs font-bold">
                  {EQUIPMENT_DB.FILTER_PAPERS.map(p => <option key={p} value={p}>{p}</option>)}
                </select>
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-[9px] font-bold text-stone-500 uppercase mb-1">Bloom (s)</label>
                  <input type="number" value={bloomTime} onChange={e => setBloomTime(Number(e.target.value))} className="w-full bg-white border border-amber-200 rounded-xl p-3 text-xs font-bold" />
                </div>
                <div>
                  <label className="block text-[9px] font-bold text-stone-500 uppercase mb-1">Pours (Count)</label>
                  <input type="number" value={pulsesCount} onChange={e => setPulsesCount(Number(e.target.value))} className="w-full bg-white border border-amber-200 rounded-xl p-3 text-xs font-bold" />
                </div>
              </div>
              <div>
                <label className="block text-[9px] font-bold text-stone-500 uppercase mb-1">Volumes (g sequence)</label>
                <input type="text" value={pourVolumes} onChange={e => setPourVolumes(e.target.value)} className="w-full bg-white border border-amber-200 rounded-xl p-3 text-xs font-bold" placeholder="e.g. 50, 70, 70, 60" />
              </div>
            </div>
          )}

          {method === BrewMethod.AEROPRESS && (
            <div className="space-y-4">
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-[9px] font-bold text-stone-500 uppercase mb-1">Brew Style</label>
                  <select value={aeroMethod} onChange={e => setAeroMethod(e.target.value)} className="w-full bg-white border border-amber-200 rounded-xl p-3 text-xs font-bold">
                    {EQUIPMENT_DB.AEROPRESS_STYLES.map(s => <option key={s} value={s}>{s}</option>)}
                  </select>
                </div>
                <div>
                  <label className="block text-[9px] font-bold text-stone-500 uppercase mb-1">Filter Cap</label>
                  <select value={filterCap} onChange={e => setFilterCap(e.target.value)} className="w-full bg-white border border-amber-200 rounded-xl p-3 text-xs font-bold">
                    {EQUIPMENT_DB.AEROPRESS_CAPS.map(c => <option key={c} value={c}>{c}</option>)}
                  </select>
                </div>
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-[9px] font-bold text-stone-500 uppercase mb-1">Steep Time (s)</label>
                  <input type="number" value={steepTimeAP} onChange={e => setSteepTimeAP(Number(e.target.value))} className="w-full bg-white border border-amber-200 rounded-xl p-3 text-xs font-bold" />
                </div>
                <div>
                  <label className="block text-[9px] font-bold text-stone-500 uppercase mb-1">Plunge Time (s)</label>
                  <input type="number" value={plungeTime} onChange={e => setPlungeTime(Number(e.target.value))} className="w-full bg-white border border-amber-200 rounded-xl p-3 text-xs font-bold" />
                </div>
              </div>
              <div>
                <label className="block text-[9px] font-bold text-stone-500 uppercase mb-1">Volumes (g sequence)</label>
                <input type="text" value={aeroPourVolumes} onChange={e => setAeroPourVolumes(e.target.value)} className="w-full bg-white border border-amber-200 rounded-xl p-3 text-xs font-bold" placeholder="e.g. 50 (bloom), 200 (fill)" />
              </div>
            </div>
          )}

          {method === BrewMethod.FRENCH_PRESS && (
            <div className="space-y-4">
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-[9px] font-bold text-stone-500 uppercase mb-1">Vessel Brand</label>
                  <select value={fpBrand} onChange={e => setFpBrand(e.target.value)} className="w-full bg-white border border-amber-200 rounded-xl p-3 text-xs font-bold">
                    {EQUIPMENT_DB.FRENCH_PRESS_BRANDS.map(b => <option key={b} value={b}>{b}</option>)}
