                  </select>
                </div>
              </div>
              <div>
                <label className="block text-[9px] font-bold text-stone-500 uppercase mb-1">Agitation Duration (s)</label>
                <input type="number" value={fpAgitationDuration} onChange={e => setFpAgitationDuration(Number(e.target.value))} className="w-full bg-white border border-amber-200 rounded-xl p-3 text-xs font-bold" />
