];

const FEATURED_BARISTAS: UserProfile[] = [
  { id: 'u1', name: 'James Hoffmann', handle: '@jimseven', avatar: 'https://picsum.photos/id/64/100/100', bio: 'London based coffee person.', friendsCount: 120, followingCount: 300, isFeatured: true },
  { id: 'u2', name: 'Lance Hedrick', handle: '@lance_h', avatar: 'https://picsum.photos/id/91/100/100', bio: 'Washed process extremist.', friendsCount: 89, followingCount: 150, isFeatured: true },
  { id: 'u3', name: 'Morgan Drinks Coffee', handle: '@morgandrinkscoffee', avatar: 'https://picsum.photos/id/102/100/100', bio: 'Barista Champion and content creator.', friendsCount: 450, followingCount: 210, isFeatured: true }
];

const INITIAL_COFFEES: CoffeeBean[] = [
  {
    id: '1',
    name: 'Ethiopia Sidamo',
    roaster: 'Proud Mary',
    origin: 'Ethiopia',
    process: 'Washed',
    roastLevel: RoastLevel.LIGHT,
    purchaseDate: '2024-03-01',
    remainingWeight: 180,
    totalWeight: 250,
    personalNotes: 'Floral and tea-like.'
  }
];

const App: React.FC = () => {
  const [coffees, setCoffees] = useState<CoffeeBean[]>(INITIAL_COFFEES);
  const [brewLogs, setBrewLogs] = useState<BrewLog[]>([]);
  const [activeTab, setActiveTab] = useState<'weekly' | 'journal' | 'library' | 'community' | 'grind'>('journal');

  // Modals & Flow State
  const [showBeanForm, setShowBeanForm] = useState(false);
  const [showBrewFlow, setShowBrewFlow] = useState(false);
  const [brewFlowStep, setBrewFlowStep] = useState<'select' | 'new-bean' | 'brew'>('select');
  const [selectedCoffee, setSelectedCoffee] = useState<CoffeeBean | null>(null);

  const handleAddBean = (bean: CoffeeBean) => {
    setCoffees(prev => [bean, ...prev]);
    if (brewFlowStep === 'new-bean') {
      setSelectedCoffee(bean);
      setBrewFlowStep('brew');
    } else {
      setShowBeanForm(false);
    }
  };

  const handleSaveBrew = (log: Partial<BrewLog>) => {
    const newLog = { 
      ...log, 
      id: Math.random().toString(36).substr(2, 9),
      date: new Date().toISOString()
    } as BrewLog;

    setBrewLogs(prev => [newLog, ...prev]);

    // Update inventory
    setCoffees(prev => prev.map(c => 
      c.id === log.coffeeId 
        ? { ...c, remainingWeight: Math.max(0, c.remainingWeight - (log.dose || 0)) } 
        : c
    ));

    // Reset Flow
    setShowBrewFlow(false);
    setBrewFlowStep('select');
    setSelectedCoffee(null);
  };

  const startBrewCapture = () => {
    setBrewFlowStep('select');
    setShowBrewFlow(true);
  };

  return (
    <div className="min-h-screen pb-32 flex flex-col bg-[#fdfcfb]">
      <header className="bg-white border-b border-stone-100 sticky top-0 z-30 px-6 py-4 flex justify-between items-center shadow-sm">
        <h1 className="text-2xl font-bold display-font text-stone-800">Barista <span className="text-amber-800">JournalPro</span></h1>
        <div className="flex items-center gap-3">
          <div className="w-8 h-8 rounded-full bg-stone-100 border border-stone-200 overflow-hidden ring-2 ring-white shadow-sm">
            <img src="https://picsum.photos/100/100" alt="Avatar" />
          </div>
        </div>
      </header>

      <main className="flex-1 max-w-2xl mx-auto w-full p-6">
        {activeTab === 'journal' && (
          <div className="animate-in fade-in slide-in-from-bottom-4 duration-500">
            <div className="flex justify-between items-center mb-8">
              <h2 className="text-3xl font-bold text-stone-800 display-font">Daily Journal</h2>
              <button 
                onClick={startBrewCapture}
                className="bg-amber-800 text-white p-4 px-6 rounded-2xl flex items-center gap-2 text-[10px] font-black uppercase tracking-[0.2em] shadow-xl shadow-amber-900/20 active:scale-95 transition-all"
              >
                <Icons.Plus className="w-4 h-4" /> Capture Brew
              </button>
            </div>

            {brewLogs.length === 0 ? (
              <div className="text-center py-24 bg-white rounded-[2.5rem] border-2 border-dashed border-stone-200">
                <Icons.Coffee className="w-16 h-16 text-stone-100 mx-auto mb-4" />
                <p className="text-stone-400 font-bold uppercase text-[10px] tracking-widest">Your journal is empty</p>
                <button onClick={startBrewCapture} className="mt-4 text-amber-800 font-bold text-sm underline underline-offset-4">Log your first calibration</button>
              </div>
            ) : (
              <div className="space-y-6">
                {brewLogs.map(log => {
                  const coffee = coffees.find(c => c.id === log.coffeeId);
                  return (
                    <div key={log.id} className="bg-white p-7 rounded-[2.5rem] shadow-sm border border-stone-100 hover:border-amber-200 transition-all group relative overflow-hidden">
                      <div className="flex justify-between mb-5">
                        <div className="flex-1">
                          <div className="flex flex-wrap items-center gap-2 mb-2">
                            <span className="text-[9px] uppercase font-black text-amber-800 bg-amber-50 px-2 py-0.5 rounded-md">{log.method}</span>
                            {log.machine && <span className="text-[9px] uppercase font-bold text-stone-500 bg-stone-50 px-2 py-0.5 rounded-md">{log.machine}</span>}
                            {log.coldBrewSystem && <span className="text-[9px] uppercase font-bold text-stone-500 bg-stone-50 px-2 py-0.5 rounded-md">{log.coldBrewSystem}</span>}
                            {log.brewerBrand && <span className="text-[9px] uppercase font-bold text-stone-500 bg-stone-50 px-2 py-0.5 rounded-md">{log.brewerBrand} {log.brewer}</span>}
                            {log.aeroMethod && <span className="text-[9px] uppercase font-bold text-stone-500 bg-stone-50 px-2 py-0.5 rounded-md">{log.aeroMethod}</span>}
                          </div>
                          <h3 className="font-bold text-2xl text-stone-800 leading-tight">{coffee?.name || 'Unknown Blend'}</h3>
                          <p className="text-[10px] text-stone-400 font-black uppercase tracking-widest mt-1.5 flex flex-wrap items-center gap-2">
                             {log.grinder} • <span className="text-amber-700">{log.grindSetting}</span>
                             {log.distributionTool && log.distributionTool !== 'None' && <span className="opacity-50">| Dist: {log.distributionTool}</span>}
                             {log.filterType && <span className="opacity-50">| Filter: {log.filterType}</span>}
                             {log.filterCapUsed && <span className="opacity-50">| Cap: {log.filterCapUsed}</span>}
                             {log.agitation && log.agitation !== 'None' && <span className="opacity-50">| Agit: {log.agitation}</span>}
                             {log.method === BrewMethod.MOKA_POT && log.isAeropressFilterUsed && <span className="opacity-50">| +Paper Filter</span>}
                          </p>
                        </div>
                        <div className="text-right">
                          <p className="text-[10px] text-stone-300 font-black uppercase tracking-tighter">{new Date(log.date).toLocaleDateString()}</p>
                          <div className="flex gap-0.5 text-amber-500 mt-2">
                            {[...Array(5)].map((_, i) => (
                              <Icons.Star key={i} className={`w-3.5 h-3.5 ${i < log.rating ? 'fill-current' : 'text-stone-100'}`} />
                            ))}
                          </div>
                        </div>
                      </div>

                      <div className="grid grid-cols-4 gap-4 bg-stone-50/80 p-5 rounded-2xl text-center mb-4">
                        <div className="flex flex-col"><p className="text-[9px] text-stone-400 font-black uppercase mb-1">Dose</p><p className="font-black text-stone-800 text-sm">{log.dose}g</p></div>
                        <div className="flex flex-col"><p className="text-[9px] text-stone-400 font-black uppercase mb-1">Yield</p><p className="font-black text-stone-800 text-sm">{log.yield}g</p></div>
                        <div className="flex flex-col">
                          <p className="text-[9px] text-stone-400 font-black uppercase mb-1">{log.method === BrewMethod.COLD_BREW ? 'Steep' : 'Time'}</p>
                          <p className="font-black text-stone-800 text-sm">
                            {log.method === BrewMethod.COLD_BREW ? `${log.steepTime}h` : `${log.brewTime}s`}
                          </p>
                        </div>
                        <div className="flex flex-col"><p className="text-[9px] text-stone-400 font-black uppercase mb-1">Temp</p><p className="font-black text-stone-800 text-sm">{log.waterTemp}°C</p></div>
                      </div>

                      {log.method === BrewMethod.POUR_OVER && (log.bloomTime || log.pourStructure || log.pourVolumes) && (
                        <div className="mb-4 grid grid-cols-2 gap-4 text-[10px] font-bold text-stone-500 bg-stone-50/50 p-3 rounded-xl">
                          {log.bloomTime && <div><span className="text-stone-300 uppercase block mb-1">Bloom</span>{log.bloomTime}s</div>}
                          {log.pourStructure && <div><span className="text-stone-300 uppercase block mb-1">Pours</span>{log.pourStructure}</div>}
                          {log.pourVolumes && <div className="col-span-2"><span className="text-stone-300 uppercase block mb-1">Volumes</span>{log.pourVolumes}</div>}
                        </div>
                      )}

                      {log.method === BrewMethod.AEROPRESS && (log.steepTime || log.plungeTime || log.aeroPourVolumes) && (
                        <div className="mb-4 grid grid-cols-2 gap-4 text-[10px] font-bold text-stone-500 bg-stone-50/50 p-3 rounded-xl">
                          {log.steepTime && <div><span className="text-stone-300 uppercase block mb-1">Steep</span>{log.steepTime}s</div>}
                          {log.plungeTime && <div><span className="text-stone-300 uppercase block mb-1">Plunge</span>{log.plungeTime}s</div>}
                          {log.aeroPourVolumes && <div className="col-span-2"><span className="text-stone-300 uppercase block mb-1">Volumes</span>{log.aeroPourVolumes}</div>}
                        </div>
                      )}

                      {log.method === BrewMethod.FRENCH_PRESS && (log.timeBeforePlunge || log.agitation) && (
                        <div className="mb-4 grid grid-cols-2 gap-4 text-[10px] font-bold text-stone-500 bg-stone-50/50 p-3 rounded-xl">
                          {log.timeBeforePlunge && <div><span className="text-stone-300 uppercase block mb-1">Plunge Wait</span>{log.timeBeforePlunge}s</div>}
                          {log.agitation && <div><span className="text-stone-300 uppercase block mb-1">Agitation</span>{log.agitation} {log.agitationDuration ? `(${log.agitationDuration}s)` : ''}</div>}
                        </div>
                      )}

                      {log.method === BrewMethod.MOKA_POT && (log.waterStartTemp || log.flameControl) && (
                        <div className="mb-4 grid grid-cols-2 gap-4 text-[10px] font-bold text-stone-500 bg-stone-50/50 p-3 rounded-xl">
                          {log.waterStartTemp && <div><span className="text-stone-300 uppercase block mb-1">Start Temp</span>{log.waterStartTemp}</div>}
                          {log.flameControl && <div><span className="text-stone-300 uppercase block mb-1">Flame Setting</span>{log.flameControl}</div>}
                        </div>
                      )}

                      {log.processNotes && (
                        <div className="mb-4 p-4 bg-amber-50/30 rounded-xl border border-amber-100/50">
                          <p className="text-[9px] font-black text-amber-800 uppercase tracking-widest mb-1">Method Notes</p>
                          <p className="text-xs text-stone-600 leading-relaxed font-medium whitespace-pre-wrap italic">"{log.processNotes}"</p>
                        </div>
                      )}

                      {log.tastingNotes && log.tastingNotes.length > 0 && (
                        <div className="flex flex-wrap gap-2">
                          {log.tastingNotes.map((note, idx) => (
                            <span key={idx} className="text-[9px] font-black text-stone-400 uppercase tracking-widest bg-stone-100 px-2 py-1 rounded-md">
                              {note}
                            </span>
                          ))}
                        </div>
                      )}
                    </div>
                  );
                })}
              </div>
            )}
          </div>
        )}

        {activeTab === 'library' && (
          <div className="animate-in fade-in slide-in-from-bottom-4 duration-500">
            <div className="flex justify-between items-center mb-8">
              <h2 className="text-3xl font-bold text-stone-800 display-font">Coffee Library</h2>
              <button onClick={() => setShowBeanForm(true)} className="bg-stone-900 text-white p-4 px-6 rounded-2xl flex items-center gap-2 text-[10px] font-black uppercase tracking-[0.2em] active:scale-95 transition-all shadow-xl shadow-stone-900/10">
                <Icons.Plus className="w-4 h-4" /> Add Bean
              </button>
            </div>
            <div className="grid grid-cols-1 gap-6">
              {coffees.map(coffee => (
                <CoffeeCard key={coffee.id} coffee={coffee} onClick={(c) => { setSelectedCoffee(c); setBrewFlowStep('brew'); setShowBrewFlow(true); }} />
              ))}
            </div>
          </div>
        )}

        {activeTab === 'grind' && <GrindReference />}

        {activeTab === 'community' && (
           <div className="animate-in fade-in slide-in-from-bottom-4 duration-500 py-12 text-center">
              <div className="w-20 h-20 bg-amber-100 rounded-[2rem] flex items-center justify-center mx-auto mb-6 text-amber-800">
                <Icons.Users className="w-8 h-8" />
              </div>
              <h3 className="text-2xl font-bold display-font mb-2">Community Feed</h3>
              <p className="text-stone-400 text-sm font-medium mb-8">Coming soon: Share your calibration recipes with baristas worldwide.</p>
              <button className="bg-stone-900 text-white px-8 py-4 rounded-2xl font-black uppercase text-[10px] tracking-widest opacity-50 cursor-not-allowed">Join Waitlist</button>
           </div>
        )}
      </main>

      {/* MODALS */}
      {showBrewFlow && (
        <div className="fixed inset-0 bg-stone-900/60 backdrop-blur-md flex items-center justify-center z-[70] p-6 overflow-y-auto">
          {brewFlowStep === 'select' && (
            <div className="bg-white rounded-[3rem] w-full max-w-md p-10 shadow-2xl animate-in zoom-in-95 duration-300">
              <div className="flex justify-between items-center mb-8">
                <div>
                   <h3 className="text-2xl font-black text-stone-800 display-font">Select Roast</h3>
                   <p className="text-xs text-stone-400 font-medium">Which bean are we calibrating today?</p>
                </div>
                <button onClick={() => setShowBrewFlow(false)} className="p-2 bg-stone-50 rounded-full text-stone-400 hover:text-stone-800 transition-colors">✕</button>
              </div>
              <div className="space-y-4 max-h-96 overflow-y-auto mb-8 pr-2 custom-scrollbar">
                {coffees.map(c => (
                  <button key={c.id} onClick={() => { setSelectedCoffee(c); setBrewFlowStep('brew'); }} className="w-full text-left p-5 rounded-[1.5rem] border border-stone-100 hover:border-amber-400 hover:bg-amber-50/50 transition-all flex justify-between items-center group">
                    <div>
                      <p className="font-black text-stone-800 group-hover:text-amber-900">{c.name}</p>
                      <p className="text-[10px] text-stone-400 font-black uppercase tracking-widest">{c.roaster}</p>
                    </div>
                    <div className="text-right">
                      <span className="text-[10px] font-black text-amber-800 bg-amber-100 px-2 py-1 rounded-md">{c.remainingWeight}g</span>
                    </div>
                  </button>
                ))}
              </div>
              <button 
                onClick={() => setBrewFlowStep('new-bean')}
                className="w-full py-5 border-2 border-dashed border-stone-200 text-stone-400 rounded-3xl font-black uppercase text-[10px] tracking-[0.2em] hover:border-amber-400 hover:text-amber-800 hover:bg-amber-50/30 transition-all"
              >
                + Register New Bean
              </button>
            </div>
          )}

          {brewFlowStep === 'new-bean' && (
            <CoffeeBeanForm 
              onSave={handleAddBean} 
              onCancel={() => setBrewFlowStep('select')} 
            />
          )}

          {brewFlowStep === 'brew' && selectedCoffee && (
            <BrewForm 
              coffee={selectedCoffee} 
              onSave={handleSaveBrew} 
              onCancel={() => setBrewFlowStep('select')} 
            />
          )}
        </div>
      )}

      {showBeanForm && (
        <div className="fixed inset-0 bg-stone-900/60 backdrop-blur-md flex items-center justify-center z-[70] p-6 overflow-y-auto">
          <CoffeeBeanForm onSave={handleAddBean} onCancel={() => setShowBeanForm(false)} />
        </div>
      )}

      <nav className="fixed bottom-6 left-1/2 -translate-x-1/2 w-[calc(100%-3rem)] max-w-md bg-stone-900/90 backdrop-blur-xl border border-white/10 px-5 py-5 flex justify-around items-center z-50 rounded-[3rem] shadow-2xl">
        {[
          { id: 'journal', icon: <Icons.Book className="w-6 h-6" />, label: 'Journal' },
          { id: 'library', icon: <Icons.Coffee className="w-6 h-6" />, label: 'Library' },
          { id: 'grind', icon: <Icons.Search className="w-6 h-6" />, label: 'Reference' },
          { id: 'community', icon: <Icons.Users className="w-6 h-6" />, label: 'Community' }
        ].map(item => (
          <button key={item.id} onClick={() => setActiveTab(item.id as any)} className={`flex flex-col items-center gap-1.5 transition-all group ${activeTab === item.id ? 'text-amber-400' : 'text-stone-500 hover:text-stone-300'}`}>
            <div className={`p-2.5 rounded-2xl transition-all ${activeTab === item.id ? 'bg-amber-400/10 scale-110 shadow-inner' : 'group-hover:bg-white/5'}`}>{item.icon}</div>
            <span className={`text-[8px] font-black uppercase tracking-[0.3em] ${activeTab === item.id ? 'opacity-100' : 'opacity-40'}`}>{item.label}</span>
          </button>
        ))}
      </nav>
    </div>
  );
};

export default App;

