  coldBrewSystem?: string;

  // Sensory Analysis (1-5 scale)
  aroma: number;
  acidity: number;
  sweetness: number;
  bitterness: number;
  body: number;
  aftertaste: number;

  // Flavor Categories
  flavorGroups: string[];
}

