};

const RadarChart: React.FC<{ log: BrewLog }> = ({ log }) => {
  const size = 120;
  const center = size / 2;
  const radius = size * 0.4;
  const points = [
    log.aroma || 3,
    log.acidity || 3,
    log.sweetness || 3,
    log.bitterness || 3,
    log.body || 3,
    log.aftertaste || 3
  ];

  const getCoordinates = (index: number, value: number) => {
    const angle = (Math.PI * 2 * index) / points.length - Math.PI / 2;
    const r = (value / 5) * radius;
    return {
      x: center + r * Math.cos(angle),
      y: center + r * Math.sin(angle)
    };
  };

  const pathData = points.map((v, i) => {
    const coords = getCoordinates(i, v);
    return `${coords.x},${coords.y}`;
  }).join(' ');

  const gridLevels = [1, 2, 3, 4, 5];

  return (
    <div className="relative w-32 h-32 flex items-center justify-center">
      <svg width={size} height={size} className="overflow-visible">
        {/* Background Grid */}
        {gridLevels.map(level => (
          <polygon
            key={level}
            points={points.map((_, i) => {
              const coords = getCoordinates(i, level);
              return `${coords.x},${coords.y}`;
            }).join(' ')}
            fill="none"
            stroke="#e5e7eb"
            strokeWidth="0.5"
          />
        ))}
        {/* Axis Lines */}
        {points.map((_, i) => {
          const end = getCoordinates(i, 5);
          return (
            <line
              key={i}
              x1={center}
              y1={center}
              x2={end.x}
              y2={end.y}
              stroke="#e5e7eb"
              strokeWidth="0.5"
            />
          );
        })}
        {/* The Data Polygon */}
        <polygon
          points={pathData}
          fill="rgba(146, 64, 14, 0.15)"
          stroke="#92400e"
          strokeWidth="2"
          strokeLinejoin="round"
        />
        {/* Icons/Labels at the points */}
        {SENSORY_METADATA.map((meta, i) => {
          const pos = getCoordinates(i, 6);
          return (
            <text
              key={meta.id}
              x={pos.x}
              y={pos.y}
              fontSize="10"
              textAnchor="middle"
              dominantBaseline="middle"
            >
              {meta.icon}
            </text>
          );
        })}
      </svg>
    </div>
  );
};

