const RadarChart: React.FC<{ log: BrewLog }> = ({ log }) => {
  const size = 130;
  const center = size / 2;
  const radius = size * 0.35;
  const points = [
    log.aroma || 3,
    log.acidity || 3,
    log.sweetness || 3,
    log.bitterness || 3,
    log.body || 3,
    log.aftertaste || 3
  ];

  const getCoordinates = (index: number, value: number) => {
    const angle = (Math.PI * 2 * index) / points.length - Math.PI / 2;
    const r = (value / 5) * radius;
    return {
      x: center + r * Math.cos(angle),
      y: center + r * Math.sin(angle)
    };
  };

  const pathData = points.map((v, i) => {
    const coords = getCoordinates(i, v);
    return `${coords.x},${coords.y}`;
  }).join(' ');

  const gridLevels = [1, 2, 3, 4, 5];

  return (
    <div className="relative w-36 h-36 flex items-center justify-center">
      <svg width={size} height={size} className="overflow-visible">
        {/* Background Grid */}
        {gridLevels.map(level => (
          <polygon
            key={level}
            points={[0,1,2,3,4,5].map((_, i) => {
              const coords = getCoordinates(i, level);
              return `${coords.x},${coords.y}`;
            }).join(' ')}
            fill="none"
            stroke="#f1f1f1"
            strokeWidth="1"
          />
        ))}
        {/* Axis Lines */}
        {points.map((_, i) => {
          const end = getCoordinates(i, 5);
          return (
            <line
              key={i}
              x1={center}
              y1={center}
              x2={end.x}
              y2={end.y}
              stroke="#f5f5f5"
              strokeWidth="1"
            />
          );
        })}
        {/* The Data Polygon - Stylized */}
        <polygon
          points={pathData}
          fill="rgba(146, 64, 14, 0.08)"
          stroke="#92400e"
          strokeWidth="2.5"
          strokeLinejoin="round"
          className="animate-in fade-in duration-1000"
        />
        {/* Data Vertices */}
        {points.map((v, i) => {
          const coords = getCoordinates(i, v);
          return (
            <circle
              key={i}
              cx={coords.x}
              cy={coords.y}
              r="2.5"
              fill="#92400e"
            />
          );
        })}
        {/* Icons/Labels at the points - Consistency in color/iconography */}
        {SENSORY_METADATA.map((meta, i) => {
          const pos = getCoordinates(i, 6.2);
          return (
            <g key={meta.id}>
              <text
                x={pos.x}
                y={pos.y}
                fontSize="12"
                textAnchor="middle"
                dominantBaseline="middle"
              >
                {meta.icon}
              </text>
              <text
                x={pos.x}
                y={pos.y + 12}
                fontSize="7"
                fontWeight="900"
                textAnchor="middle"
                dominantBaseline="middle"
                fill={meta.color}
                className="uppercase tracking-tighter"
              >
                {meta.label}
              </text>
            </g>
          );
        })}
      </svg>
    </div>
  );
};

